function getWatValueType(valueType: CompilerValueType): string {
  switch (valueType) {
    case 'f64':
    case 'i32':
      return valueType;
    case 'heap_ref':
    case 'class_constructor_ref':
    case 'string_ref':
      return 'externref';
    case 'symbol_ref':
      return '(ref null $symbol_runtime)';
    case 'bigint_ref':
      return '(ref null $bigint_runtime)';
    case 'owned_string_ref':
      return '(ref null $string_runtime)';
    case 'owned_heap_array_ref':
      return '(ref null $owned_heap_array)';
    case 'owned_array_ref':
      return '(ref null $owned_string_array)';
    case 'owned_number_array_ref':
      return '(ref null $owned_number_array)';
    case 'owned_boolean_array_ref':
      return '(ref null $owned_boolean_array)';
    case 'owned_tagged_array_ref':
      return '(ref null $owned_tagged_array)';
    case 'tagged_ref':
      return '(ref null $tagged_value)';
    case 'box_ref':
      return '(ref null eq)';
    case 'closure_ref':
      return '(ref null $closure)';
    default: {
      const exhaustiveCheck: never = valueType;
      return exhaustiveCheck;
    }
  }
}

