function expressionUsesStringLength(expression: CompilerExpressionIR): boolean {
  switch (expression.kind) {
    case 'string_length':
    case 'string_code_point_at':
      return true;
    case 'string_trim':
    case 'string_trim_start':
    case 'string_trim_end':
    case 'string_to_upper_case':
    case 'string_to_lower_case':
      return expressionUsesStringLength(expression.value);
    case 'string_substring':
      return expressionUsesStringLength(expression.value) ||
        expressionUsesStringLength(expression.start) ||
        (expression.end ? expressionUsesStringLength(expression.end) : false);
    case 'string_char_at':
      return expressionUsesStringLength(expression.value) ||
        expressionUsesStringLength(expression.index);
    case 'string_char_code_at':
      return expressionUsesStringLength(expression.value) ||
        expressionUsesStringLength(expression.index);
    case 'binary':
      return expressionUsesStringLength(expression.left) ||
        expressionUsesStringLength(expression.right);
    case 'call':
      return expression.args.some(expressionUsesStringLength);
    default:
      return false;
  }
}

