function forEachExpressionChild(
  expression: CompilerExpressionIR,
  visit: (child: CompilerExpressionIR) => void,
): void {
  switch (expression.kind) {
    case 'string_length':
    case 'owned_string_length':
    case 'string_to_upper_case':
    case 'string_to_lower_case':
    case 'owned_string_to_upper_case':
    case 'owned_string_to_lower_case':
    case 'string_trim':
    case 'string_trim_start':
    case 'string_trim_end':
    case 'owned_string_trim':
    case 'owned_string_trim_start':
    case 'owned_string_trim_end':
    case 'owned_string_to_host':
    case 'string_to_owned':
    case 'tag_number':
    case 'tag_boolean':
    case 'tag_string':
    case 'tag_symbol':
    case 'tag_bigint':
    case 'tag_heap_object':
    case 'untag_number':
    case 'untag_boolean':
    case 'untag_owned_string':
    case 'untag_symbol':
    case 'untag_bigint':
    case 'untag_heap_object':
    case 'tagged_is_undefined':
    case 'tagged_is_null':
    case 'tagged_has_tag':
    case 'tagged_is_closure':
    case 'tagged_is_array':
    case 'tagged_array_length':
    case 'class_instanceof':
    case 'builtin_error_instanceof':
      visit(expression.value);
      break;
    case 'tagged_array_element':
      visit(expression.value);
      visit(expression.index);
      break;
    case 'box_new':
      visit(expression.value);
      break;
    case 'box_get':
      visit(expression.box);
      break;
    case 'string_char_at':
    case 'owned_string_char_at':
    case 'string_char_code_at':
    case 'owned_string_char_code_at':
    case 'string_code_point_at':
    case 'owned_string_code_point_at':
      visit(expression.value);
      visit(expression.index);
      break;
    case 'string_starts_with':
    case 'string_ends_with':
    case 'string_includes':
    case 'owned_string_starts_with':
    case 'owned_string_ends_with':
    case 'owned_string_includes':
    case 'owned_string_index_of':
    case 'owned_string_last_index_of':
    case 'string_index_of':
    case 'string_last_index_of':
      visit(expression.value);
      visit(expression.search);
      break;
    case 'string_slice':
    case 'string_substring':
    case 'owned_string_slice':
    case 'owned_string_substring':
      visit(expression.value);
      visit(expression.start);
      if (expression.end) {
        visit(expression.end);
      }
      break;
    case 'owned_array_length':
      visit(expression.value);
      break;
    case 'owned_string_array_literal':
    case 'owned_heap_array_literal':
    case 'owned_number_array_literal':
    case 'owned_boolean_array_literal':
    case 'owned_tagged_array_literal':
      expression.elements.forEach(visit);
      break;
    case 'owned_string_concat':
      visit(expression.left);
      visit(expression.right);
      break;
    case 'owned_string_array_join':
    case 'owned_number_array_join':
    case 'owned_boolean_array_join':
      visit(expression.array);
      visit(expression.separator);
      visit(expression.empty);
      break;
    case 'owned_heap_array_splice':
    case 'owned_string_array_splice':
    case 'owned_number_array_splice':
    case 'owned_boolean_array_splice':
    case 'owned_tagged_array_splice':
      visit(expression.array);
      visit(expression.start);
      visit(expression.deleteCount);
      visit(expression.items);
      break;
    case 'owned_string_array_unshift':
    case 'owned_number_array_unshift':
    case 'owned_boolean_array_unshift':
    case 'owned_tagged_array_unshift':
    case 'owned_heap_array_unshift':
      visit(expression.array);
      visit(expression.value);
      break;
    case 'owned_heap_array_pop':
    case 'owned_heap_array_shift':
    case 'owned_string_array_pop':
    case 'owned_string_array_shift':
    case 'owned_number_array_shift':
    case 'owned_boolean_array_shift':
    case 'owned_number_array_pop':
    case 'owned_boolean_array_pop':
    case 'owned_tagged_array_pop':
    case 'owned_tagged_array_shift':
      visit(expression.array);
      break;
    case 'owned_string_array_unshift':
    case 'owned_number_array_unshift':
    case 'owned_boolean_array_unshift':
    case 'owned_tagged_array_unshift':
      visit(expression.array);
      visit(expression.value);
      break;
    case 'owned_string_array_element':
    case 'owned_heap_array_element':
    case 'owned_number_array_element':
    case 'owned_boolean_array_element':
    case 'owned_tagged_array_element':
      visit(expression.value);
      visit(expression.index);
      break;
    case 'owned_heap_array_at':
    case 'owned_string_array_at':
    case 'owned_number_array_at':
    case 'owned_boolean_array_at':
    case 'owned_tagged_array_at':
      visit(expression.array);
      visit(expression.index);
      break;
    case 'owned_heap_array_reverse':
    case 'owned_heap_array_fill':
    case 'owned_string_array_reverse':
    case 'owned_number_array_reverse':
    case 'owned_boolean_array_reverse':
    case 'owned_tagged_array_reverse':
      visit(expression.array);
      break;
    case 'owned_heap_array_fill':
    case 'owned_string_array_fill':
    case 'owned_number_array_fill':
    case 'owned_boolean_array_fill':
    case 'owned_tagged_array_fill':
      visit(expression.array);
      visit(expression.value);
      visit(expression.start);
      if (expression.end) {
        visit(expression.end);
      }
      break;
    case 'owned_heap_array_copy_within':
    case 'owned_string_array_copy_within':
    case 'owned_number_array_copy_within':
    case 'owned_boolean_array_copy_within':
    case 'owned_tagged_array_copy_within':
      visit(expression.array);
      visit(expression.target);
      visit(expression.start);
      if (expression.end) {
        visit(expression.end);
      }
      break;
    case 'owned_heap_array_concat':
    case 'owned_string_array_concat':
    case 'owned_number_array_concat':
    case 'owned_boolean_array_concat':
    case 'owned_tagged_array_concat':
      visit(expression.left);
      visit(expression.right);
      break;
    case 'owned_heap_array_slice':
    case 'owned_string_array_slice':
    case 'owned_number_array_slice':
    case 'owned_boolean_array_slice':
    case 'owned_tagged_array_slice':
      visit(expression.array);
      visit(expression.start);
      if (expression.end) {
        visit(expression.end);
      }
      break;
    case 'owned_heap_array_includes':
    case 'owned_heap_array_index_of':
    case 'owned_string_array_includes':
    case 'owned_number_array_includes':
    case 'owned_boolean_array_includes':
    case 'owned_tagged_array_includes':
    case 'owned_string_array_index_of':
    case 'owned_number_array_index_of':
    case 'owned_boolean_array_index_of':
    case 'owned_tagged_array_index_of':
    case 'owned_heap_array_last_index_of':
    case 'owned_string_array_last_index_of':
    case 'owned_number_array_last_index_of':
    case 'owned_boolean_array_last_index_of':
    case 'owned_tagged_array_last_index_of':
      visit(expression.array);
      visit(expression.search);
      if (expression.fromIndex) {
        visit(expression.fromIndex);
      }
      break;
    case 'owned_heap_array_push':
    case 'owned_heap_array_unshift':
    case 'owned_string_array_push':
    case 'owned_number_array_push':
    case 'owned_boolean_array_push':
    case 'owned_tagged_array_push':
      visit(expression.array);
      visit(expression.value);
      break;
    case 'binary':
      visit(expression.left);
      visit(expression.right);
      break;
    case 'closure_call':
      visit(expression.callee);
      expression.args.forEach(visit);
      break;
    case 'call':
      expression.args.forEach(visit);
      break;
    default:
      break;
  }
}

function collectOwnedStringLiteralIds(
  expression: CompilerExpressionIR,
  literalIds: Set<number>,
): void {
  if (expression.kind === 'owned_string_literal') {
    literalIds.add(expression.literalId);
  }
  forEachExpressionChild(expression, (child) => collectOwnedStringLiteralIds(child, literalIds));
}

