function collectOwnedArrayAliasNames(
  func: CompilerFunctionIR,
  paramName: string,
  kind: 'string' | 'number' | 'boolean',
): ReadonlySet<string> {
  const targetType = kind === 'string'
    ? 'owned_array_ref'
    : kind === 'number'
    ? 'owned_number_array_ref'
    : 'owned_boolean_array_ref';
  const localTypes = new Map(
    [...func.params, ...func.locals].map((local) => [local.name, local.type] as const),
  );
  const aliasNames = new Set<string>([paramName]);
  let changed = true;
  const visitStatements = (statements: readonly CompilerStatementIR[]): void => {
    for (const statement of statements) {
      switch (statement.kind) {
        case 'local_set':
          if (
            localTypes.get(statement.name) === targetType &&
            statement.value.kind === 'local_get' &&
            aliasNames.has(statement.value.name)
          ) {
            aliasNames.add(statement.name);
          }
          break;
        case 'if':
          visitStatements(statement.thenBody);
          visitStatements(statement.elseBody);
          break;
        case 'while':
          visitStatements(statement.body);
          break;
        default:
          break;
      }
    }
  };
  while (changed) {
    const before = aliasNames.size;
    visitStatements(func.body);
    changed = aliasNames.size !== before;
  }
  return aliasNames;
}

function expressionMutatesOwnedArrayParam(
  expression: CompilerExpressionIR,
  matchingNames: ReadonlySet<string>,
  kind: 'string' | 'number' | 'boolean',
): boolean {
  const isMatchingArrayLocal = (candidate: CompilerExpressionIR): boolean =>
    candidate.kind === 'local_get' &&
    matchingNames.has(candidate.name) &&
    candidate.type === (
        kind === 'string'
          ? 'owned_array_ref'
          : kind === 'number'
          ? 'owned_number_array_ref'
          : 'owned_boolean_array_ref'
      );
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_push') ||
    (kind === 'number' && expression.kind === 'owned_number_array_push') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_push')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_unshift') ||
    (kind === 'number' && expression.kind === 'owned_number_array_unshift') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_unshift')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_pop') ||
    (kind === 'number' && expression.kind === 'owned_number_array_pop') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_pop')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_shift') ||
    (kind === 'number' && expression.kind === 'owned_number_array_shift') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_shift')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_reverse') ||
    (kind === 'number' && expression.kind === 'owned_number_array_reverse') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_reverse')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_fill') ||
    (kind === 'number' && expression.kind === 'owned_number_array_fill') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_fill')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_copy_within') ||
    (kind === 'number' && expression.kind === 'owned_number_array_copy_within') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_copy_within')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  if (
    (kind === 'string' && expression.kind === 'owned_string_array_splice') ||
    (kind === 'number' && expression.kind === 'owned_number_array_splice') ||
    (kind === 'boolean' && expression.kind === 'owned_boolean_array_splice')
  ) {
    return isMatchingArrayLocal(expression.array);
  }
  let mutates = false;
  forEachExpressionChild(expression, (child) => {
    if (!mutates && expressionMutatesOwnedArrayParam(child, matchingNames, kind)) {
      mutates = true;
    }
  });
  return mutates;
}

function statementMutatesOwnedArrayParam(
  statement: CompilerStatementIR,
  matchingNames: ReadonlySet<string>,
  kind: 'string' | 'number' | 'boolean',
): boolean {
  switch (statement.kind) {
    case 'expression':
      return expressionMutatesOwnedArrayParam(statement.value, matchingNames, kind);
    case 'global_set':
    case 'local_set':
      return expressionMutatesOwnedArrayParam(statement.value, matchingNames, kind);
    case 'return':
    case 'specialized_object_field_set':
      return expressionMutatesOwnedArrayParam(statement.value, matchingNames, kind);
    case 'owned_heap_array_set':
      return expressionMutatesOwnedArrayParam(statement.array, matchingNames, kind) ||
        expressionMutatesOwnedArrayParam(statement.index, matchingNames, kind) ||
        expressionMutatesOwnedArrayParam(statement.value, matchingNames, kind);
    case 'owned_string_array_set':
      return kind === 'string' && statement.array.kind === 'local_get' &&
        matchingNames.has(statement.array.name);
    case 'owned_number_array_set':
      return kind === 'number' && statement.array.kind === 'local_get' &&
        matchingNames.has(statement.array.name);
    case 'owned_boolean_array_set':
      return kind === 'boolean' && statement.array.kind === 'local_get' &&
        matchingNames.has(statement.array.name);
    case 'owned_tagged_array_set':
      return expressionMutatesOwnedArrayParam(statement.array, matchingNames, kind) ||
        expressionMutatesOwnedArrayParam(statement.index, matchingNames, kind) ||
        expressionMutatesOwnedArrayParam(statement.value, matchingNames, kind);
    case 'if':
      return statement.thenBody.some((child) =>
        statementMutatesOwnedArrayParam(child, matchingNames, kind)
      ) || statement.elseBody.some((child) =>
        statementMutatesOwnedArrayParam(child, matchingNames, kind)
      );
    case 'while':
      return statement.body.some((child) =>
        statementMutatesOwnedArrayParam(child, matchingNames, kind)
      );
    default:
      return false;
  }
}

function functionOwnedArrayParamNeedsHostSync(
  func: CompilerFunctionIR,
  paramName: string,
  kind: 'string' | 'number' | 'boolean',
): boolean {
  const aliasNames = collectOwnedArrayAliasNames(func, paramName, kind);
  return func.body.some((statement) =>
    statementMutatesOwnedArrayParam(statement, aliasNames, kind)
  );
}

