function encodeWatIdentifierHex(text: string): string {
  return [...new TextEncoder().encode(text)]
    .map((byte) => byte.toString(16).padStart(2, '0'))
    .join('');
}

function getHostObjectLookupParamCachedImportFunctionName(cacheKey: string): string {
  return `host_object_lookup_param_cached__${encodeWatIdentifierHex(cacheKey)}`;
}

function getHostObjectRememberParamCachedImportFunctionName(cacheKey: string): string {
  return `host_object_remember_param_cached__${encodeWatIdentifierHex(cacheKey)}`;
}

const HOST_FALLBACK_PARAM_CACHE_KEY = 'fallback_object';

const HOST_FALLBACK_OBJECT_VALUE_KINDS: CompilerTaggedPrimitiveBoundaryKindsIR = {
  includesBoolean: true,
  includesNull: true,
  includesNumber: true,
  includesString: true,
  includesUndefined: true,
};

function taggedBoundaryKindsEqual(
  left: CompilerTaggedPrimitiveBoundaryKindsIR,
  right: CompilerTaggedPrimitiveBoundaryKindsIR,
): boolean {
  return left.includesBoolean === right.includesBoolean &&
    left.includesNull === right.includesNull &&
    left.includesNumber === right.includesNumber &&
    left.includesString === right.includesString &&
    left.includesUndefined === right.includesUndefined;
}

function taggedArrayBoundaryEqual(
  left: CompilerFunctionHostTaggedArrayBoundaryIR,
  right: CompilerFunctionHostTaggedArrayBoundaryIR,
): boolean {
  return taggedBoundaryKindsEqual(left, right) &&
    left.representation?.kind === right.representation?.kind &&
    left.representation?.name === right.representation?.name;
}

function getHostFallbackObjectParamBoundaryNames(func: CompilerFunctionIR): string[] {
  return getEffectiveHostFallbackObjectParamBoundaryNames(func);
}

function hasHostFallbackObjectResultBoundary(func: CompilerFunctionIR): boolean {
  return hasEffectiveHostFallbackObjectResultBoundary(func);
}

function getHostTaggedHeapNullableFallbackParamBoundaryNames(func: CompilerFunctionIR): string[] {
  return [
    ...getEffectiveHostTaggedHeapNullableParamsByName(func).values(),
    ...(func.hostUnionBoundaryParams ?? []).flatMap((param) => {
      const representation = getFiniteUnionHeapRepresentation(param.boundary);
      return representation?.kind === 'fallback_object_representation'
        ? [
          {
            name: param.name,
            includesNull: false,
            includesUndefined: false,
            representation,
          } satisfies CompilerFunctionHostTaggedHeapNullableParamIR,
        ]
        : [];
    }),
  ]
    .filter((boundary) => boundary.representation.kind === 'fallback_object_representation')
    .map((boundary) => boundary.name);
}

function hasHostTaggedHeapNullableFallbackResultBoundary(func: CompilerFunctionIR): boolean {
  return getEffectiveHostTaggedHeapNullableResultBoundary(func)?.representation.kind ===
      'fallback_object_representation' ||
    getFiniteUnionHeapRepresentation(func.hostUnionBoundaryResult)?.kind ===
      'fallback_object_representation';
}

function collectHostBoundaryFallbackObjectUsage(
  module: CompilerModuleIR,
): {
  needsParamBoundary: boolean;
  needsParamCopyBack: boolean;
  needsResultBoundary: boolean;
} | undefined {
  let needsParamBoundary = false;
  let needsParamCopyBack = false;
  let needsResultBoundary = false;
  for (const func of module.functions) {
    const hostHeapArrayParamsByName = getEffectiveHostHeapArrayParamsByName(func);
    const hostHeapArrayResultRepresentation = getEffectiveHostHeapArrayResultRepresentation(func);
    const hostTaggedArrayParamsByName = getEffectiveHostTaggedArrayParamsByName(func);
    const hostTaggedArrayResultKinds = getEffectiveHostTaggedArrayResultKinds(func);
    const paramBoundaries = getHostFallbackObjectParamBoundaryNames(func);
    const finiteUnionFallbackParamBoundary = (func.hostUnionBoundaryParams ?? []).some((param) =>
      getFiniteUnionHeapRepresentation(param.boundary)?.kind === 'fallback_object_representation'
    );
    if (paramBoundaries.length > 0) {
      needsParamBoundary = true;
      needsParamCopyBack = true;
    }
    if (finiteUnionFallbackParamBoundary) {
      needsParamBoundary = true;
      needsParamCopyBack = true;
      needsResultBoundary = true;
    }
    const nullableParamBoundaries = getHostTaggedHeapNullableFallbackParamBoundaryNames(func);
    if (nullableParamBoundaries.length > 0) {
      needsParamBoundary = true;
      needsParamCopyBack = true;
    }
    if (
      [...hostHeapArrayParamsByName.values()].some((representation) =>
        representation.kind === 'fallback_object_representation'
      )
    ) {
      needsParamBoundary = true;
      needsParamCopyBack = true;
      needsResultBoundary = true;
    }
    if (
      [...hostTaggedArrayParamsByName.values()].some((boundary) =>
        boundary.representation?.kind === 'fallback_object_representation'
      )
    ) {
      needsParamBoundary = true;
      needsParamCopyBack = true;
      needsResultBoundary = true;
    }
    if (
      hasHostFallbackObjectResultBoundary(func) ||
      hasHostTaggedHeapNullableFallbackResultBoundary(func) ||
      getFiniteUnionHeapRepresentation(func.hostUnionBoundaryResult)?.kind ===
        'fallback_object_representation' ||
      hostHeapArrayResultRepresentation?.kind === 'fallback_object_representation' ||
      hostTaggedArrayResultKinds?.representation?.kind === 'fallback_object_representation'
    ) {
      needsResultBoundary = true;
    }
  }
  return needsParamBoundary || needsParamCopyBack || needsResultBoundary
    ? { needsParamBoundary, needsParamCopyBack, needsResultBoundary }
    : undefined;
}

function getEffectiveHostFallbackObjectMetadata(module: CompilerModuleIR): ReturnType<
  typeof getEffectiveHostFallbackObjectPropertyMetadata
> {
  return getEffectiveHostFallbackObjectPropertyMetadata(module);
}

function collectHostBoundaryFallbackPropertyNames(module: CompilerModuleIR): string[] {
  const keys = new Set(getEffectiveHostFallbackObjectMetadata(module).propertyNames);
  for (const runtimeFunction of module.runtime?.functions ?? []) {
    for (const operation of runtimeFunction.operations) {
      switch (operation.kind) {
        case 'allocate_fallback_object':
          for (const entry of operation.entries) {
            keys.add(entry.key);
          }
          break;
        case 'get_fallback_object_property':
        case 'has_fallback_object_property':
        case 'set_fallback_object_property':
          keys.add(operation.propertyKey);
          break;
        case 'adapt_value':
          if (operation.family === 'object') {
            for (const entry of operation.fallbackMaterialization?.entries ?? []) {
              keys.add(entry.key);
            }
          }
          break;
      }
    }
  }
  return [...keys].sort((left, right) => left.localeCompare(right));
}

