function getHostObjectToFallbackHelperName(): string {
  return 'host_object_to_fallback_object';
}

function getCopyFallbackObjectToHostHelperName(): string {
  return 'copy_fallback_object_to_host_object';
}

function getFallbackObjectToHostHelperName(): string {
  return 'fallback_object_to_host_object';
}

function getHostObjectGetterKind(
  field: BackendSpecializedObjectFieldLayout,
): 'get_number' | 'get_boolean' | 'get_closure' | 'get_tagged' {
  switch (field.valueType) {
    case 'f64':
      return 'get_number';
    case 'i32':
      return 'get_boolean';
    case 'class_constructor_ref':
      return 'get_tagged';
    case 'closure_ref':
      return 'get_closure';
    case 'tagged_ref':
    case 'heap_ref':
    case 'owned_heap_array_ref':
    case 'owned_array_ref':
    case 'owned_number_array_ref':
    case 'owned_boolean_array_ref':
    case 'owned_tagged_array_ref':
      return 'get_tagged';
    default:
      throw createUnsupportedHeapRuntimeBackendError(
        `Unsupported host specialized getter kind for field ${field.name}.`,
      );
  }
}

function getHostObjectSetterKind(
  field: BackendSpecializedObjectFieldLayout,
): 'set_number' | 'set_boolean' | 'set_closure' | 'set_tagged' {
  switch (field.valueType) {
    case 'f64':
      return 'set_number';
    case 'i32':
      return 'set_boolean';
    case 'class_constructor_ref':
      return 'set_tagged';
    case 'closure_ref':
      return 'set_closure';
    case 'tagged_ref':
    case 'heap_ref':
    case 'owned_heap_array_ref':
    case 'owned_array_ref':
    case 'owned_number_array_ref':
    case 'owned_boolean_array_ref':
    case 'owned_tagged_array_ref':
      return 'set_tagged';
    default:
      throw createUnsupportedHeapRuntimeBackendError(
        `Unsupported host specialized setter kind for field ${field.name}.`,
      );
  }
}

function getHostObjectFieldWatType(field: BackendSpecializedObjectFieldLayout): string {
  switch (field.valueType) {
    case 'f64':
      return 'f64';
    case 'i32':
      return 'i32';
    case 'class_constructor_ref':
      return 'externref';
    case 'closure_ref':
      return 'externref';
    case 'tagged_ref':
    case 'heap_ref':
    case 'owned_heap_array_ref':
    case 'owned_array_ref':
    case 'owned_number_array_ref':
    case 'owned_boolean_array_ref':
    case 'owned_tagged_array_ref':
      return 'externref';
    default:
      throw createUnsupportedHeapRuntimeBackendError(
        `Unsupported host specialized field type for ${field.name}.`,
      );
  }
}

function emitHostClassConstructorFieldToHost(
  field: BackendSpecializedObjectFieldLayout,
  layout: BackendSpecializedObjectLayout,
  level: number,
  targetLocalName: string,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
): string[] {
  if (field.classTagId === undefined) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Missing class constructor tag metadata for field ${field.name}.`,
    );
  }
  if (field.classTagId === layout.classTagId) {
    return [
      `${indent(level)}local.get $${targetLocalName}`,
      `${indent(level)}local.get $${targetLocalName}`,
      `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
    ];
  }
  const targetLayout = [...layoutsByRepresentationName.values()].find((candidate) =>
    candidate.classTagId === field.classTagId
  );
  return [
    `${indent(level)}local.get $${targetLocalName}`,
    ...(targetLayout
      ? [`${indent(level)}call $${getHostClassConstructorToHostHelperName(targetLayout)}`]
      : [
        `${indent(level)}i32.const ${field.classTagId}`,
        `${indent(level)}call $${getHostObjectClassConstructorFromTagImportFunctionName()}`,
      ]),
    `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
  ];
}

function emitHostFallbackClassConstructorPropertyToHost(
  propertyName: string,
  classTagId: number,
  level: number,
  targetLocalName: string,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
): string[] {
  const targetLayout = [...layoutsByRepresentationName.values()].find((candidate) =>
    candidate.classTagId === classTagId
  );
  return [
    `${indent(level)}local.get $${targetLocalName}`,
    ...(targetLayout
      ? [`${indent(level)}call $${getHostClassConstructorToHostHelperName(targetLayout)}`]
      : [
        `${indent(level)}i32.const ${classTagId}`,
        `${indent(level)}call $${getHostObjectClassConstructorFromTagImportFunctionName()}`,
      ]),
    `${indent(level)}call $${getHostFallbackObjectSetImportFunctionName(propertyName)}`,
  ];
}

function emitHostSpecializedFieldFromHostForTarget(
  field: BackendSpecializedObjectFieldLayout,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
  level: number,
  targetLocalName: string,
): string[] {
  if (field.valueType === 'class_constructor_ref') {
    return [];
  }
  const getterLines = [
    `${indent(level)}local.get $${targetLocalName}`,
    `${indent(level)}call $${
      getHostObjectImportFunctionName(getHostObjectGetterKind(field), field.name)
    }`,
  ];
  if (field.valueType === 'closure_ref') {
    return [
      ...getterLines,
      `${indent(level)}call $host_externref_to_closure_${field.closureSignatureId}`,
    ];
  }
  if (field.valueType === 'tagged_ref') {
    if (field.boundary?.kind === 'tagged' && field.boundary.heapBoundary?.kind === 'closure') {
      return [
        ...getterLines,
        `${indent(level)}local.set $entry_value`,
        ...emitHostTaggedPrimitiveAndClosureToInternal(
          'entry_value',
          'entry_tag',
          'entry_tagged',
          field.boundary,
          level,
        ),
      ];
    }
    if (!field.taggedPrimitiveKinds) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing tagged field metadata for ${field.name}.`,
      );
    }
    return [
      ...getterLines,
      `${indent(level)}local.set $entry_value`,
      ...(field.heapRepresentation
        ? emitHostClosureTaggedPrimitiveAndHeapToInternal(
          'entry_value',
          'entry_tag',
          'entry_tagged',
          field.taggedPrimitiveKinds,
          field.heapRepresentation,
          level,
          layoutsByRepresentationName,
        )
        : emitHostTaggedPrimitiveExternrefToTagged(
          'entry_value',
          'entry_tag',
          'entry_tagged',
          field.taggedPrimitiveKinds,
          level,
          indent,
        )),
    ];
  }
  if (field.valueType === 'heap_ref') {
    if (!field.heapRepresentation) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing heap representation metadata for field ${field.name}.`,
      );
    }
    if (field.promiseBridge) {
      return [
        ...getterLines,
        `${indent(level)}call $${SOUNDSCRIPT_PROMISE_NEW_PENDING_HELPER_NAME}`,
        `${indent(level)}call ${SOUNDSCRIPT_HOST_PROMISE_TO_INTERNAL_IMPORT_NAME}`,
      ];
    }
    return [
      ...getterLines,
      `${indent(level)}call $${
        field.heapRepresentation.kind === 'specialized_object_representation'
          ? getHostObjectToSpecializedHelperName(
            getLayoutForRepresentationName(
              field.heapRepresentation.name,
              layoutsByRepresentationName,
            ),
          )
          : getHostObjectToFallbackHelperName()
      }`,
    ];
  }
  if (field.valueType === 'owned_heap_array_ref') {
    if (!field.heapArrayRepresentation) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing heap-array representation metadata for field ${field.name}.`,
      );
    }
    return [
      ...getterLines,
      `${indent(level)}call $${
        getHostArrayToOwnedHeapArrayHelperName(field.heapArrayRepresentation)
      }`,
    ];
  }
  if (field.valueType === 'owned_tagged_array_ref') {
    if (!field.taggedPrimitiveKinds) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing tagged-array field metadata for field ${field.name}.`,
      );
    }
    return [
      ...getterLines,
      `${indent(level)}call $${
        getHostArrayToOwnedTaggedArrayHelperName({
          ...field.taggedPrimitiveKinds,
          representation: field.heapRepresentation,
        })
      }`,
    ];
  }
  if (isOwnedScalarArrayFieldValueType(field.valueType)) {
    return [
      ...getterLines,
      `${indent(level)}call $${getHostArrayToOwnedHelperName(field.valueType)}`,
    ];
  }
  return getterLines;
}

function emitHostSpecializedFieldFromHost(
  field: BackendSpecializedObjectFieldLayout,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
  level: number,
): string[] {
  return emitHostSpecializedFieldFromHostForTarget(
    field,
    layoutsByRepresentationName,
    level,
    'value',
  );
}

function emitSpecializedFieldCopyFromHost(
  field: BackendSpecializedObjectFieldLayout,
  layout: BackendSpecializedObjectLayout,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
  fieldIndex: number,
  level: number,
  targetLocalName: string,
  valueLocalName: string,
): string[] {
  if (field.valueType === 'class_constructor_ref') {
    return [];
  }
  return [
    `${indent(level)}local.get $${valueLocalName}`,
    ...emitHostSpecializedFieldFromHostForTarget(
      field,
      layoutsByRepresentationName,
      level,
      targetLocalName,
    ),
    `${indent(level)}struct.set $${layout.watTypeId} ${
      getSpecializedObjectFieldSlotIndex(layout, fieldIndex)
    }`,
  ];
}

function emitSpecializedFieldCopyToHost(
  field: BackendSpecializedObjectFieldLayout,
  layout: BackendSpecializedObjectLayout,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
  fallbackObjectLayout: BackendFallbackObjectRuntimeLayout | undefined,
  fieldIndex: number,
  level: number,
): string[] {
  if (field.valueType === 'class_constructor_ref') {
    return emitHostClassConstructorFieldToHost(
      field,
      layout,
      level,
      'target',
      layoutsByRepresentationName,
    );
  }
  const fieldValueLines = [
    `${indent(level)}local.get $value`,
    `${indent(level)}struct.get $${layout.watTypeId} ${
      getSpecializedObjectFieldSlotIndex(layout, fieldIndex)
    }`,
  ];
  if (field.valueType === 'closure_ref') {
    if ((field.methodClosureFunctionIds?.length ?? 0) > 0) {
      const syncExportName = getHostSpecializedFieldMethodSyncExportName(layout, field.name);
      return [
        `${indent(level)}local.get $target`,
        `${indent(level)}local.get $target`,
        ...fieldValueLines,
        `${indent(level)}call $${
          getHostClosureToHostSyncImportFunctionName(field.closureSignatureId!, syncExportName)
        }`,
        `${indent(level)}call $${getHostObjectImportFunctionName('set_closure', field.name)}`,
      ];
    }
    return [
      `${indent(level)}local.get $target`,
      ...fieldValueLines,
      `${indent(level)}call $host_closure_to_host_${field.closureSignatureId}`,
      `${indent(level)}call $${getHostObjectImportFunctionName('set_closure', field.name)}`,
    ];
  }
  if (field.valueType === 'heap_ref') {
    if (!field.heapRepresentation) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing heap representation metadata for field ${field.name}.`,
      );
    }
    if (field.promiseBridge) {
      return [
        `${indent(level)}local.get $target`,
        ...fieldValueLines,
        `${indent(level)}call ${SOUNDSCRIPT_HOST_PROMISE_TO_HOST_IMPORT_NAME}`,
        `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      ];
    }
    const heapLayout = field.heapRepresentation.kind === 'specialized_object_representation'
      ? getLayoutForRepresentationName(field.heapRepresentation.name, layoutsByRepresentationName)
      : undefined;
    if (
      field.heapRepresentation.kind === 'fallback_object_representation' && !fallbackObjectLayout
    ) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing fallback object layout for field ${field.name}.`,
      );
    }
    return [
      ...fieldValueLines,
      `${indent(level)}local.set $entry_heap`,
      `${indent(level)}local.get $target`,
      `${indent(level)}call $${getHostObjectImportFunctionName('get_tagged', field.name)}`,
      `${indent(level)}local.set $entry_existing`,
      `${indent(level)}local.get $entry_heap`,
      `${indent(level)}call $${getHostObjectLookupCachedImportFunctionName()}`,
      `${indent(level)}local.set $entry_value`,
      `${indent(level)}local.get $entry_value`,
      `${indent(level)}ref.is_null`,
      `${indent(level)}if`,
      `${indent(level + 1)}local.get $target`,
      `${indent(level + 1)}local.get $entry_heap`,
      ...(field.heapRepresentation.kind === 'specialized_object_representation'
        ? [
          `${indent(level + 1)}ref.cast (ref null $${heapLayout!.watTypeId})`,
          `${indent(level + 1)}call $${getSpecializedObjectToHostHelperName(heapLayout!)}`,
        ]
        : [
          `${indent(level + 1)}ref.cast (ref null $${fallbackObjectLayout!.watTypeId})`,
          `${indent(level + 1)}call $${getFallbackObjectToHostHelperName()}`,
        ]),
      `${indent(level + 1)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      `${indent(level)}else`,
      `${indent(level + 1)}local.get $entry_existing`,
      `${indent(level + 1)}local.get $entry_value`,
      `${indent(level + 1)}call $host_object_same`,
      `${indent(level + 1)}if`,
      `${indent(level + 2)}local.get $entry_existing`,
      `${indent(level + 2)}local.get $entry_heap`,
      ...(field.heapRepresentation.kind === 'specialized_object_representation'
        ? [
          `${indent(level + 2)}ref.cast (ref null $${heapLayout!.watTypeId})`,
          `${indent(level + 2)}call $${getCopySpecializedObjectToHostHelperName(heapLayout!)}`,
        ]
        : [
          `${indent(level + 2)}ref.cast (ref null $${fallbackObjectLayout!.watTypeId})`,
          `${indent(level + 2)}call $${getCopyFallbackObjectToHostHelperName()}`,
        ]),
      `${indent(level + 1)}else`,
      `${indent(level + 2)}local.get $target`,
      `${indent(level + 2)}local.get $entry_heap`,
      ...(field.heapRepresentation.kind === 'specialized_object_representation'
        ? [
          `${indent(level + 2)}ref.cast (ref null $${heapLayout!.watTypeId})`,
          `${indent(level + 2)}call $${getSpecializedObjectToHostHelperName(heapLayout!)}`,
        ]
        : [
          `${indent(level + 2)}ref.cast (ref null $${fallbackObjectLayout!.watTypeId})`,
          `${indent(level + 2)}call $${getFallbackObjectToHostHelperName()}`,
        ]),
      `${indent(level + 2)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      `${indent(level + 1)}end`,
      `${indent(level)}end`,
    ];
  }
  if (field.valueType === 'tagged_ref') {
    if (field.boundary?.kind === 'tagged' && field.boundary.heapBoundary?.kind === 'closure') {
      return [
        `${indent(level)}local.get $target`,
        ...fieldValueLines,
        `${indent(level)}local.set $entry_tagged`,
        ...emitInternalTaggedPrimitiveAndClosureToHost(
          'entry_tagged',
          'entry_tag',
          'entry_value',
          field.boundary,
          level,
        ),
        `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      ];
    }
    if (!field.taggedPrimitiveKinds) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing tagged field metadata for ${field.name}.`,
      );
    }
    return [
      `${indent(level)}local.get $target`,
      ...fieldValueLines,
      `${indent(level)}local.set $entry_tagged`,
      ...(field.heapRepresentation
        ? emitInternalClosureTaggedPrimitiveAndHeapToHost(
          'entry_tagged',
          'entry_tag',
          'entry_value',
          field.taggedPrimitiveKinds,
          field.heapRepresentation,
          level,
          layoutsByRepresentationName,
          fallbackObjectLayout,
        )
        : emitTaggedPrimitiveToHostExternref(
          'entry_tagged',
          'entry_tag',
          'entry_value',
          field.taggedPrimitiveKinds,
          level,
          indent,
        )),
      `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
    ];
  }
  if (field.valueType === 'owned_heap_array_ref') {
    if (!field.heapArrayRepresentation) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing heap-array representation metadata for field ${field.name}.`,
      );
    }
    return [
      `${indent(level)}local.get $target`,
      `${indent(level)}call $${getHostObjectImportFunctionName('get_tagged', field.name)}`,
      ...fieldValueLines,
      `${indent(level)}call $${
        getCopyOwnedHeapArrayToHostHelperName(field.heapArrayRepresentation)
      }`,
    ];
  }
  if (field.valueType === 'owned_tagged_array_ref') {
    if (!field.taggedPrimitiveKinds) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing tagged-array field metadata for field ${field.name}.`,
      );
    }
    return [
      `${indent(level)}local.get $target`,
      `${indent(level)}call $${getHostObjectImportFunctionName('get_tagged', field.name)}`,
      ...fieldValueLines,
      `${indent(level)}call $${
        getCopyOwnedTaggedArrayToHostHelperName({
          ...field.taggedPrimitiveKinds,
          representation: field.heapRepresentation,
        })
      }`,
    ];
  }
  if (isOwnedScalarArrayFieldValueType(field.valueType)) {
    return [
      `${indent(level)}local.get $target`,
      `${indent(level)}call $${getHostObjectImportFunctionName('get_tagged', field.name)}`,
      ...fieldValueLines,
      `${indent(level)}call $${getOwnedArrayCopyToHostHelperName(field.valueType)}`,
    ];
  }
  return [
    `${indent(level)}local.get $target`,
    ...fieldValueLines,
    `${indent(level)}call $${
      getHostObjectImportFunctionName(getHostObjectSetterKind(field), field.name)
    }`,
  ];
}

function emitSpecializedFieldResultToHost(
  field: BackendSpecializedObjectFieldLayout,
  layout: BackendSpecializedObjectLayout,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
  fallbackObjectLayout: BackendFallbackObjectRuntimeLayout | undefined,
  fieldIndex: number,
  level: number,
): string[] {
  if (field.valueType === 'class_constructor_ref') {
    return emitHostClassConstructorFieldToHost(
      field,
      layout,
      level,
      'result',
      layoutsByRepresentationName,
    );
  }
  const fieldValueLines = [
    `${indent(level)}local.get $result`,
    `${indent(level)}local.get $value`,
    `${indent(level)}struct.get $${layout.watTypeId} ${
      getSpecializedObjectFieldSlotIndex(layout, fieldIndex)
    }`,
  ];
  if (field.valueType === 'closure_ref') {
    if ((field.methodClosureFunctionIds?.length ?? 0) > 0) {
      const syncExportName = getHostSpecializedFieldMethodSyncExportName(layout, field.name);
      return [
        `${indent(level)}local.get $result`,
        ...fieldValueLines,
        `${indent(level)}call $${
          getHostClosureToHostSyncImportFunctionName(field.closureSignatureId!, syncExportName)
        }`,
        `${indent(level)}call $${getHostObjectImportFunctionName('set_closure', field.name)}`,
      ];
    }
    return [
      ...fieldValueLines,
      `${indent(level)}call $host_closure_to_host_${field.closureSignatureId}`,
      `${indent(level)}call $${getHostObjectImportFunctionName('set_closure', field.name)}`,
    ];
  }
  if (field.valueType === 'heap_ref') {
    if (!field.heapRepresentation) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing heap representation metadata for field ${field.name}.`,
      );
    }
    if (field.promiseBridge) {
      return [
        ...fieldValueLines,
        `${indent(level)}call ${SOUNDSCRIPT_HOST_PROMISE_TO_HOST_IMPORT_NAME}`,
        `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      ];
    }
    const heapLayout = field.heapRepresentation.kind === 'specialized_object_representation'
      ? getLayoutForRepresentationName(field.heapRepresentation.name, layoutsByRepresentationName)
      : undefined;
    if (
      field.heapRepresentation.kind === 'fallback_object_representation' && !fallbackObjectLayout
    ) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing fallback object layout for field ${field.name}.`,
      );
    }
    return [
      `${indent(level)}local.get $value`,
      `${indent(level)}struct.get $${layout.watTypeId} ${
        getSpecializedObjectFieldSlotIndex(layout, fieldIndex)
      }`,
      `${indent(level)}local.set $entry_heap`,
      `${indent(level)}local.get $entry_heap`,
      `${indent(level)}call $${getHostObjectLookupCachedImportFunctionName()}`,
      `${indent(level)}local.set $entry_existing`,
      `${indent(level)}local.get $entry_existing`,
      `${indent(level)}ref.is_null`,
      `${indent(level)}if`,
      `${indent(level + 1)}local.get $result`,
      `${indent(level + 1)}local.get $entry_heap`,
      ...(field.heapRepresentation.kind === 'specialized_object_representation'
        ? [
          `${indent(level + 1)}ref.cast (ref null $${heapLayout!.watTypeId})`,
          `${indent(level + 1)}call $${getSpecializedObjectToHostHelperName(heapLayout!)}`,
        ]
        : [
          `${indent(level + 1)}ref.cast (ref null $${fallbackObjectLayout!.watTypeId})`,
          `${indent(level + 1)}call $${getFallbackObjectToHostHelperName()}`,
        ]),
      `${indent(level + 1)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      `${indent(level)}else`,
      `${indent(level + 1)}local.get $entry_existing`,
      `${indent(level + 1)}local.get $entry_heap`,
      ...(field.heapRepresentation.kind === 'specialized_object_representation'
        ? [
          `${indent(level + 1)}ref.cast (ref null $${heapLayout!.watTypeId})`,
          `${indent(level + 1)}call $${getCopySpecializedObjectToHostHelperName(heapLayout!)}`,
        ]
        : [
          `${indent(level + 1)}ref.cast (ref null $${fallbackObjectLayout!.watTypeId})`,
          `${indent(level + 1)}call $${getCopyFallbackObjectToHostHelperName()}`,
        ]),
      `${indent(level + 1)}local.get $result`,
      `${indent(level + 1)}local.get $entry_existing`,
      `${indent(level + 1)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      `${indent(level)}end`,
    ];
  }
  if (field.valueType === 'tagged_ref') {
    if (field.boundary?.kind === 'tagged' && field.boundary.heapBoundary?.kind === 'closure') {
      return [
        ...fieldValueLines,
        `${indent(level)}local.set $entry_tagged`,
        ...emitInternalTaggedPrimitiveAndClosureToHost(
          'entry_tagged',
          'entry_tag',
          'entry_value',
          field.boundary,
          level,
        ),
        `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
      ];
    }
    if (!field.taggedPrimitiveKinds) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing tagged field metadata for ${field.name}.`,
      );
    }
    return [
      ...fieldValueLines,
      `${indent(level)}local.set $entry_tagged`,
      ...(field.heapRepresentation
        ? emitInternalClosureTaggedPrimitiveAndHeapToHost(
          'entry_tagged',
          'entry_tag',
          'entry_value',
          field.taggedPrimitiveKinds,
          field.heapRepresentation,
          level,
          layoutsByRepresentationName,
          fallbackObjectLayout,
        )
        : emitTaggedPrimitiveToHostExternref(
          'entry_tagged',
          'entry_tag',
          'entry_value',
          field.taggedPrimitiveKinds,
          level,
          indent,
        )),
      `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
    ];
  }
  if (field.valueType === 'owned_heap_array_ref') {
    if (!field.heapArrayRepresentation) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing heap-array representation metadata for field ${field.name}.`,
      );
    }
    return [
      ...fieldValueLines,
      `${indent(level)}call $${getOwnedHeapArrayToHostHelperName(field.heapArrayRepresentation)}`,
      `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
    ];
  }
  if (field.valueType === 'owned_tagged_array_ref') {
    if (!field.taggedPrimitiveKinds) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Missing tagged-array field metadata for field ${field.name}.`,
      );
    }
    return [
      ...fieldValueLines,
      `${indent(level)}call $${
        getOwnedTaggedArrayToHostHelperName({
          ...field.taggedPrimitiveKinds,
          representation: field.heapRepresentation,
        })
      }`,
      `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
    ];
  }
  if (isOwnedScalarArrayFieldValueType(field.valueType)) {
    return [
      ...fieldValueLines,
      `${indent(level)}call $${getOwnedArrayHostResultHelperName(field.valueType)}`,
      `${indent(level)}call $${getHostObjectImportFunctionName('set_tagged', field.name)}`,
    ];
  }
  return [
    ...fieldValueLines,
    `${indent(level)}call $${
      getHostObjectImportFunctionName(getHostObjectSetterKind(field), field.name)
    }`,
  ];
}

function collectHostBoundarySpecializedObjectUsage(
  module: CompilerModuleIR,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
): Map<
  string,
  {
    layout: BackendSpecializedObjectLayout;
    needsParamBoundary: boolean;
    needsParamCopyBack: boolean;
    needsResultBoundary: boolean;
  }
> {
  const usageByRepresentationName = new Map<
    string,
    {
      layout: BackendSpecializedObjectLayout;
      needsParamBoundary: boolean;
      needsParamCopyBack: boolean;
      needsResultBoundary: boolean;
    }
  >();
  const recordHostPromiseValueBoundaryUsage = (
    valueBoundary: CompilerHostBoundaryIR | undefined,
  ): void => {
    if (!valueBoundary) {
      return;
    }
    switch (valueBoundary.kind) {
      case 'object':
        if (valueBoundary.representation.kind === 'specialized_object_representation') {
          recordUsage(
            valueBoundary.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        return;
      case 'tagged':
        if (
          valueBoundary.heapBoundary?.kind === 'object' &&
          valueBoundary.heapBoundary.representation.kind === 'specialized_object_representation'
        ) {
          recordUsage(
            valueBoundary.heapBoundary
              .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        if (
          valueBoundary.heapBoundary?.kind === 'array' &&
          valueBoundary.heapBoundary.carrierType === 'owned_heap_array_ref' &&
          valueBoundary.heapBoundary.elementBoundary.kind === 'object' &&
          valueBoundary.heapBoundary.elementBoundary.representation.kind ===
            'specialized_object_representation'
        ) {
          recordUsage(
            valueBoundary.heapBoundary.elementBoundary
              .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        if (
          valueBoundary.heapBoundary?.kind === 'array' &&
          valueBoundary.heapBoundary.carrierType === 'owned_tagged_array_ref' &&
          valueBoundary.heapBoundary.elementBoundary.kind === 'object' &&
          valueBoundary.heapBoundary.elementBoundary.representation.kind ===
            'specialized_object_representation'
        ) {
          recordUsage(
            valueBoundary.heapBoundary.elementBoundary
              .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        return;
      case 'array':
        if (
          valueBoundary.carrierType === 'owned_heap_array_ref' &&
          valueBoundary.elementBoundary.kind === 'object' &&
          valueBoundary.elementBoundary.representation.kind === 'specialized_object_representation'
        ) {
          recordUsage(
            valueBoundary.elementBoundary
              .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        if (
          valueBoundary.carrierType === 'owned_tagged_array_ref' &&
          valueBoundary.elementBoundary.kind === 'object' &&
          valueBoundary.elementBoundary.representation.kind ===
            'specialized_object_representation'
        ) {
          recordUsage(
            valueBoundary.elementBoundary
              .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        return;
      default:
        return;
    }
  };
  const recordUsage = (
    representation: CompilerRuntimeSpecializedObjectRepresentationRefIR,
    updates: {
      needsParamBoundary?: boolean;
      needsParamCopyBack?: boolean;
      needsResultBoundary?: boolean;
    },
    visiting: Set<string> = new Set(),
  ): void => {
    if (visiting.has(representation.name)) {
      return;
    }
    visiting.add(representation.name);
    const layout = getLayoutForRepresentationName(representation.name, layoutsByRepresentationName);
    if (!isHostAdaptableSpecializedObjectLayout(layout)) {
      visiting.delete(representation.name);
      return;
    }
    const current = usageByRepresentationName.get(representation.name) ?? {
      layout,
      needsParamBoundary: false,
      needsParamCopyBack: false,
      needsResultBoundary: false,
    };
    current.needsParamBoundary ||= updates.needsParamBoundary === true;
    current.needsParamCopyBack ||= updates.needsParamCopyBack === true;
    current.needsResultBoundary ||= updates.needsResultBoundary === true;
    usageByRepresentationName.set(representation.name, current);
    const nestedUpdates = {
      ...updates,
      needsResultBoundary: updates.needsResultBoundary === true ||
        updates.needsParamCopyBack === true,
    };
    for (const field of layout.fields) {
      if (field.heapRepresentation?.kind === 'specialized_object_representation') {
        recordUsage(
          field.heapRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          nestedUpdates,
          visiting,
        );
      }
      if (field.heapArrayRepresentation?.kind === 'specialized_object_representation') {
        recordUsage(
          field.heapArrayRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          nestedUpdates,
          visiting,
        );
      }
    }
    if (layout.classTagId === undefined) {
      visiting.delete(representation.name);
      return;
    }
    for (
      const descendantLayout of getSpecializedSubtypeLayouts(layout, layoutsByRepresentationName)
    ) {
      if (!isHostAdaptableSpecializedObjectLayout(descendantLayout)) {
        continue;
      }
      const descendantCurrent =
        usageByRepresentationName.get(descendantLayout.representation.name) ?? {
          layout: descendantLayout,
          needsParamBoundary: false,
          needsParamCopyBack: false,
          needsResultBoundary: false,
        };
      descendantCurrent.needsParamBoundary ||= updates.needsParamBoundary === true;
      descendantCurrent.needsParamCopyBack ||= updates.needsParamCopyBack === true;
      descendantCurrent.needsResultBoundary ||= updates.needsResultBoundary === true;
      usageByRepresentationName.set(descendantLayout.representation.name, descendantCurrent);
    }
    visiting.delete(representation.name);
  };

  for (const func of module.functions) {
    const hostHeapArrayParamsByName = getEffectiveHostHeapArrayParamsByName(func);
    const hostHeapArrayResultRepresentation = getEffectiveHostHeapArrayResultRepresentation(func);
    const hostTaggedArrayParamsByName = getEffectiveHostTaggedArrayParamsByName(func);
    const hostTaggedArrayResultKinds = getEffectiveHostTaggedArrayResultKinds(func);
    recordHostPromiseValueBoundaryUsage(
      getHostPromiseBoundary(func.hostResultBoundary)?.valueBoundary,
    );
    for (const paramBoundary of func.hostParamBoundaries ?? []) {
      recordHostPromiseValueBoundaryUsage(
        getHostPromiseBoundary(paramBoundary.boundary)?.valueBoundary,
      );
    }
    for (
      const boundary of getHostAdaptableSpecializedObjectParamBoundaries(
        func,
        layoutsByRepresentationName,
      )
    ) {
      recordUsage(boundary.representation, {
        needsParamBoundary: true,
        needsParamCopyBack: true,
        needsResultBoundary: true,
      });
    }
    for (
      const boundary of getHostTaggedHeapNullableSpecializedParamBoundaries(
        func,
        layoutsByRepresentationName,
      )
    ) {
      recordUsage(
        boundary.boundary.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        {
          needsParamBoundary: true,
          needsParamCopyBack: true,
          needsResultBoundary: true,
        },
      );
    }
    for (const param of func.hostUnionBoundaryParams ?? []) {
      const representation = getFiniteUnionHeapRepresentation(param.boundary);
      if (representation?.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(representation as CompilerRuntimeSpecializedObjectRepresentationRefIR, {
        needsParamBoundary: true,
        needsParamCopyBack: true,
        needsResultBoundary: true,
      });
    }
    const resultRepresentation = getHostAdaptableSpecializedObjectResultRepresentation(
      func,
      layoutsByRepresentationName,
    );
    if (resultRepresentation) {
      recordUsage(resultRepresentation, { needsResultBoundary: true });
    }
    const taggedHeapNullableResult = getHostTaggedHeapNullableSpecializedResultRepresentation(
      func,
      layoutsByRepresentationName,
    );
    if (taggedHeapNullableResult) {
      recordUsage(
        taggedHeapNullableResult
          .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        { needsResultBoundary: true },
      );
    }
    const finiteUnionResultRepresentation = getFiniteUnionHeapRepresentation(
      func.hostUnionBoundaryResult,
    );
    if (finiteUnionResultRepresentation?.kind === 'specialized_object_representation') {
      recordUsage(
        finiteUnionResultRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        { needsResultBoundary: true },
      );
    }
    for (const [, representation] of hostHeapArrayParamsByName) {
      if (representation.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(
        representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        {
          needsParamBoundary: true,
          needsParamCopyBack: true,
          needsResultBoundary: true,
        },
      );
    }
    if (hostHeapArrayResultRepresentation?.kind === 'specialized_object_representation') {
      recordUsage(
        hostHeapArrayResultRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        { needsResultBoundary: true },
      );
    }
    for (const boundary of hostTaggedArrayParamsByName.values()) {
      if (boundary.representation?.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(
        boundary.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        {
          needsParamBoundary: true,
          needsParamCopyBack: true,
          needsResultBoundary: true,
        },
      );
    }
    if (
      hostTaggedArrayResultKinds?.representation?.kind === 'specialized_object_representation'
    ) {
      recordUsage(
        hostTaggedArrayResultKinds
          .representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        { needsResultBoundary: true },
      );
    }
    const hasFallbackParamBoundary = getHostFallbackObjectParamBoundaryNames(func).length > 0 ||
      getHostTaggedHeapNullableFallbackParamBoundaryNames(func).length > 0;
    const hasFallbackResultBoundary = hasHostFallbackObjectResultBoundary(func) ||
      hasHostTaggedHeapNullableFallbackResultBoundary(func);
    const fallbackProperties = getEffectiveFunctionHostFallbackObjectPropertyMetadata(func);
    for (const representation of fallbackProperties.heapProperties.values()) {
      if (representation.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(representation as CompilerRuntimeSpecializedObjectRepresentationRefIR, {
        needsParamBoundary: hasFallbackParamBoundary,
        needsParamCopyBack: hasFallbackParamBoundary,
        needsResultBoundary: hasFallbackParamBoundary || hasFallbackResultBoundary,
      });
    }
    for (const representation of fallbackProperties.heapArrayProperties.values()) {
      if (representation.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(representation as CompilerRuntimeSpecializedObjectRepresentationRefIR, {
        needsParamBoundary: hasFallbackParamBoundary,
        needsParamCopyBack: hasFallbackParamBoundary,
        needsResultBoundary: hasFallbackParamBoundary || hasFallbackResultBoundary,
      });
    }
    for (const property of fallbackProperties.taggedArrayProperties.values()) {
      if (property.representation?.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(property.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR, {
        needsParamBoundary: hasFallbackParamBoundary,
        needsParamCopyBack: hasFallbackParamBoundary,
        needsResultBoundary: hasFallbackParamBoundary || hasFallbackResultBoundary,
      });
    }
    for (const property of fallbackProperties.taggedHeapProperties.values()) {
      if (property.representation.kind !== 'specialized_object_representation') {
        continue;
      }
      recordUsage(property.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR, {
        needsParamBoundary: hasFallbackParamBoundary,
        needsParamCopyBack: hasFallbackParamBoundary,
        needsResultBoundary: hasFallbackParamBoundary || hasFallbackResultBoundary,
      });
    }
  }
  for (const signature of module.closureSignatures ?? []) {
    recordHostPromiseValueBoundaryUsage(signature.resultPromiseValueBoundary);
    for (const boundary of signature.paramPromiseValueBoundaries ?? []) {
      recordHostPromiseValueBoundaryUsage(boundary);
    }
  }
  return usageByRepresentationName;
}

function collectHostBoundaryFallbackObjectUsageWithHostClosures(
  module: CompilerModuleIR,
): {
  needsParamBoundary: boolean;
  needsParamCopyBack: boolean;
  needsResultBoundary: boolean;
} | undefined {
  const baseUsage = collectHostBoundaryFallbackObjectUsage(module);
  let needsParamBoundary = baseUsage?.needsParamBoundary === true;
  const needsParamCopyBack = baseUsage?.needsParamCopyBack === true;
  let needsResultBoundary = baseUsage?.needsResultBoundary === true;
  for (
    const {
      signature,
      needsParamBoundary: needsClosureParamBoundary,
      needsResultBoundary: needsClosureResultBoundary,
    } of getHostClosureBoundarySignatures(module)
  ) {
    if (
      needsClosureParamBoundary &&
      (
        signature.resultHeapRepresentation?.kind === 'fallback_object_representation' ||
        signature.resultHeapArrayRepresentation?.kind === 'fallback_object_representation'
      )
    ) {
      needsParamBoundary = true;
    }
    if (
      needsClosureParamBoundary &&
      (
        signature.paramHeapRepresentations?.some((representation) =>
          representation?.kind === 'fallback_object_representation'
        ) ||
        signature.paramHeapArrayRepresentations?.some((representation) =>
          representation?.kind === 'fallback_object_representation'
        )
      )
    ) {
      needsResultBoundary = true;
    }
    if (
      needsClosureResultBoundary &&
      (
        signature.resultHeapRepresentation?.kind === 'fallback_object_representation' ||
        signature.resultHeapArrayRepresentation?.kind === 'fallback_object_representation'
      )
    ) {
      needsResultBoundary = true;
    }
    if (
      needsClosureResultBoundary &&
      (
        signature.paramHeapRepresentations?.some((representation) =>
          representation?.kind === 'fallback_object_representation'
        ) ||
        signature.paramHeapArrayRepresentations?.some((representation) =>
          representation?.kind === 'fallback_object_representation'
        )
      )
    ) {
      needsParamBoundary = true;
    }
  }
  return needsParamBoundary || needsParamCopyBack || needsResultBoundary
    ? { needsParamBoundary, needsParamCopyBack, needsResultBoundary }
    : undefined;
}

function collectHostBoundarySpecializedObjectUsageWithHostClosures(
  module: CompilerModuleIR,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
): Map<
  string,
  {
    layout: BackendSpecializedObjectLayout;
    needsParamBoundary: boolean;
    needsParamCopyBack: boolean;
    needsResultBoundary: boolean;
  }
> {
  const usageByRepresentationName = collectHostBoundarySpecializedObjectUsage(
    module,
    layoutsByRepresentationName,
  );
  const recordUsage = (
    representation: CompilerRuntimeSpecializedObjectRepresentationRefIR,
    updates: {
      needsParamBoundary?: boolean;
      needsParamCopyBack?: boolean;
      needsResultBoundary?: boolean;
    },
  ): boolean => {
    const layout = getLayoutForRepresentationName(representation.name, layoutsByRepresentationName);
    if (!isHostAdaptableSpecializedObjectLayout(layout)) {
      return false;
    }
    const current = usageByRepresentationName.get(representation.name) ?? {
      layout,
      needsParamBoundary: false,
      needsParamCopyBack: false,
      needsResultBoundary: false,
    };
    const previousParamBoundary = current.needsParamBoundary;
    const previousParamCopyBack = current.needsParamCopyBack;
    const previousResultBoundary = current.needsResultBoundary;
    current.needsParamBoundary ||= updates.needsParamBoundary === true;
    current.needsParamCopyBack ||= updates.needsParamCopyBack === true;
    current.needsResultBoundary ||= updates.needsResultBoundary === true;
    usageByRepresentationName.set(representation.name, current);
    let changed = current.needsParamBoundary !== previousParamBoundary ||
      current.needsParamCopyBack !== previousParamCopyBack ||
      current.needsResultBoundary !== previousResultBoundary;
    if (layout.classTagId === undefined) {
      return changed;
    }
    for (
      const descendantLayout of getSpecializedSubtypeLayouts(layout, layoutsByRepresentationName)
    ) {
      if (!isHostAdaptableSpecializedObjectLayout(descendantLayout)) {
        continue;
      }
      const descendantCurrent =
        usageByRepresentationName.get(descendantLayout.representation.name) ?? {
          layout: descendantLayout,
          needsParamBoundary: false,
          needsParamCopyBack: false,
          needsResultBoundary: false,
        };
      const previousDescendantParamBoundary = descendantCurrent.needsParamBoundary;
      const previousDescendantParamCopyBack = descendantCurrent.needsParamCopyBack;
      const previousDescendantResultBoundary = descendantCurrent.needsResultBoundary;
      descendantCurrent.needsParamBoundary ||= updates.needsParamBoundary === true;
      descendantCurrent.needsParamCopyBack ||= updates.needsParamCopyBack === true;
      descendantCurrent.needsResultBoundary ||= updates.needsResultBoundary === true;
      usageByRepresentationName.set(descendantLayout.representation.name, descendantCurrent);
      changed ||= descendantCurrent.needsParamBoundary !== previousDescendantParamBoundary ||
        descendantCurrent.needsParamCopyBack !== previousDescendantParamCopyBack ||
        descendantCurrent.needsResultBoundary !== previousDescendantResultBoundary;
    }
    return changed;
  };
  const visitedClassConstructorSurfaceTags = new Set<number>();
  const markClassConstructorSurfaceUsage = (classTagId: number): void => {
    if (visitedClassConstructorSurfaceTags.has(classTagId)) {
      return;
    }
    visitedClassConstructorSurfaceTags.add(classTagId);
    const layout = [...layoutsByRepresentationName.values()].find((candidate) =>
      candidate.classTagId === classTagId
    );
    if (!layout) {
      return;
    }
    for (const field of layout.hostStaticFields) {
      if (
        field.valueKind === 'heap_object' &&
        field.representation?.kind === 'specialized_object_representation'
      ) {
        recordUsage(
          field.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsParamBoundary: true, needsResultBoundary: true },
        );
        continue;
      }
      if (
        field.valueKind === 'tagged_array' &&
        field.representation?.kind === 'specialized_object_representation'
      ) {
        recordUsage(
          field.representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsParamBoundary: true, needsResultBoundary: true },
        );
        continue;
      }
      if (field.valueKind === 'class_constructor' && field.classTagId !== undefined) {
        markClassConstructorSurfaceUsage(field.classTagId);
      }
    }
    for (const field of layout.fields) {
      if (field.valueType === 'class_constructor_ref' && field.classTagId !== undefined) {
        markClassConstructorSurfaceUsage(field.classTagId);
      }
    }
    if (layout.baseRepresentationName) {
      const baseLayout = layoutsByRepresentationName.get(layout.baseRepresentationName);
      if (baseLayout?.classTagId !== undefined) {
        markClassConstructorSurfaceUsage(baseLayout.classTagId);
      }
    }
  };
  for (const func of module.functions) {
    const fallbackProperties = getEffectiveFunctionHostFallbackObjectPropertyMetadata(func);
    const hostClassConstructorResultTagId = getEffectiveHostClassConstructorResultTagId(func);
    if (hostClassConstructorResultTagId !== undefined) {
      markClassConstructorSurfaceUsage(hostClassConstructorResultTagId);
    }
    for (const classTagId of fallbackProperties.classConstructorProperties.values()) {
      markClassConstructorSurfaceUsage(classTagId);
    }
  }
  for (const signature of module.closureSignatures ?? []) {
    if (signature.resultClassConstructorTagId !== undefined) {
      markClassConstructorSurfaceUsage(signature.resultClassConstructorTagId);
    }
    for (const param of getHostClosureSourceParamBoundaries(signature)) {
      if (param.classTagId !== undefined) {
        markClassConstructorSurfaceUsage(param.classTagId);
      }
    }
  }
  for (
    const {
      signature,
      needsParamBoundary: needsClosureParamBoundary,
      needsResultBoundary: needsClosureResultBoundary,
    } of getHostClosureBoundarySignatures(module)
  ) {
    const emitsHostClosureBranch = needsClosureParamBoundary;
    if (emitsHostClosureBranch) {
      if (signature.resultHeapRepresentation?.kind === 'specialized_object_representation') {
        recordUsage(
          signature.resultHeapRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsParamBoundary: true },
        );
      }
      if (signature.resultHeapArrayRepresentation?.kind === 'specialized_object_representation') {
        recordUsage(
          signature
            .resultHeapArrayRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsParamBoundary: true },
        );
      }
      for (const representation of signature.paramHeapRepresentations ?? []) {
        if (representation?.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
      for (const representation of signature.paramHeapArrayRepresentations ?? []) {
        if (representation?.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
      for (const param of getHostClosureSourceParamBoundaries(signature)) {
        if (param.heapRepresentation?.kind === 'specialized_object_representation') {
          recordUsage(
            param.heapRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
        if (param.heapArrayRepresentation?.kind === 'specialized_object_representation') {
          recordUsage(
            param.heapArrayRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
            { needsResultBoundary: true },
          );
        }
      }
    }
    if (
      needsClosureParamBoundary &&
      signature.resultHeapRepresentation?.kind === 'specialized_object_representation'
    ) {
      recordUsage(
        signature.resultHeapRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        { needsParamBoundary: true },
      );
    }
    if (
      needsClosureParamBoundary &&
      signature.resultHeapArrayRepresentation?.kind === 'specialized_object_representation'
    ) {
      recordUsage(
        signature
          .resultHeapArrayRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
        { needsParamBoundary: true },
      );
    }
    if (needsClosureResultBoundary) {
      if (signature.resultHeapRepresentation?.kind === 'specialized_object_representation') {
        recordUsage(
          signature.resultHeapRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
      if (signature.resultHeapArrayRepresentation?.kind === 'specialized_object_representation') {
        recordUsage(
          signature
            .resultHeapArrayRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
      for (const representation of signature.paramHeapRepresentations ?? []) {
        if (representation?.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsParamBoundary: true },
        );
      }
      for (const representation of signature.paramHeapArrayRepresentations ?? []) {
        if (representation?.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsParamBoundary: true },
        );
      }
    }
    if (needsClosureParamBoundary) {
      for (const representation of signature.paramHeapRepresentations ?? []) {
        if (representation?.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
      for (const representation of signature.paramHeapArrayRepresentations ?? []) {
        if (representation?.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
    }
  }
  if (moduleUsesGeneratorStepClosureHostBridge(module)) {
    const functionsByName = new Map(module.functions.map((func) => [func.name, func] as const));
    const fallbackObjectLayout = getFallbackObjectLayout(module.runtime);
    const dynamicObjectLayout = getDynamicObjectLayout(module.runtime);
    for (const layout of layoutsByRepresentationName.values()) {
      if (!isHostAdaptableSpecializedObjectLayout(layout)) {
        continue;
      }
      recordUsage(layout.representation, { needsResultBoundary: true });
    }
    for (const func of module.functions) {
      if (func.usesAsyncGeneratorHostStepBridge !== true) {
        continue;
      }
      const operations = getRuntimeOperationsForFunction(func, module.runtime);
      const inferredHeapLocalRepresentations = (() => {
        try {
          return inferHeapLocalRepresentations(
            func,
            operations,
            collectDynamicAllocationsByLocal(operations),
            collectSpecializedAllocationsByLocal(operations),
            collectFallbackAllocationsByLocal(operations),
            layoutsByRepresentationName,
            fallbackObjectLayout,
            dynamicObjectLayout,
            functionsByName,
          );
        } catch (error) {
          if (
            error instanceof CompilerUnsupportedError &&
            error.message.includes('changed backend heap representations within one function')
          ) {
            return new Map<string, BackendHeapRepresentation>();
          }
          throw error;
        }
      })();
      const runtimeOperationRepresentations: CompilerRuntimeRepresentationRefIR<'object'>[] = [];
      for (const operation of operations) {
        if (
          typeof operation === 'object' &&
          operation !== null &&
          'representation' in operation &&
          typeof operation.representation === 'object' &&
          operation.representation !== null &&
          'kind' in operation.representation
        ) {
          runtimeOperationRepresentations.push(
            operation.representation as CompilerRuntimeRepresentationRefIR<'object'>,
          );
        }
      }
      const runtimeRepresentations = [
        ...(func.heapLocalRepresentations?.map((entry) => entry.representation) ?? []),
        ...(func.heapParamRepresentations ?? []),
        ...(func.heapResultRepresentation ? [func.heapResultRepresentation] : []),
        ...runtimeOperationRepresentations,
        ...[...inferredHeapLocalRepresentations.values()]
          .filter((
            representation,
          ): representation is Extract<BackendHeapRepresentation, { kind: 'specialized' }> =>
            representation.kind === 'specialized'
          )
          .map((representation) => representation.layout.representation),
      ].filter((
        representation,
      ): representation is CompilerRuntimeRepresentationRefIR<'object'> =>
        typeof representation === 'object' && representation !== null && 'kind' in representation
      );
      for (const representation of runtimeRepresentations) {
        if (representation.kind !== 'specialized_object_representation') {
          continue;
        }
        recordUsage(
          representation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          { needsResultBoundary: true },
        );
      }
    }
  }
  let changed = true;
  while (changed) {
    changed = false;
    for (const usage of [...usageByRepresentationName.values()]) {
      for (const field of usage.layout.fields) {
        const nestedRepresentation = field.valueType === 'heap_ref'
          ? field.heapRepresentation
          : field.valueType === 'owned_heap_array_ref'
          ? field.heapArrayRepresentation
          : field.valueType === 'owned_tagged_array_ref'
          ? field.heapRepresentation
          : undefined;
        if (nestedRepresentation?.kind !== 'specialized_object_representation') {
          continue;
        }
        changed ||= recordUsage(
          nestedRepresentation as CompilerRuntimeSpecializedObjectRepresentationRefIR,
          {
            needsParamBoundary: usage.needsParamBoundary || usage.needsResultBoundary,
            needsParamCopyBack: usage.needsParamCopyBack || usage.needsResultBoundary,
            needsResultBoundary: usage.needsParamCopyBack || usage.needsResultBoundary,
          },
        );
      }
    }
  }
  return usageByRepresentationName;
}

function getFallbackObjectLayout(
  runtime?: CompilerRuntimeIR,
): BackendFallbackObjectRuntimeLayout | undefined {
  const representation = runtime?.representations.find((
    candidate,
  ): candidate is CompilerRuntimeFallbackObjectRepresentationIR =>
    candidate.kind === 'fallback_object_representation'
  );
  if (!representation) {
    return undefined;
  }
  return {
    occupancyArrayWatTypeId: `${sanitizeWatIdentifier(representation.name)}_occupancy_array`,
    propertyKeyArrayWatTypeId: `${sanitizeWatIdentifier(representation.name)}_property_key_array`,
    representation,
    taggedValueArrayWatTypeId: `${sanitizeWatIdentifier(representation.name)}_tagged_value_array`,
    watTypeId: sanitizeWatIdentifier(representation.name),
  };
}

function getDynamicObjectLayout(
  runtime?: CompilerRuntimeIR,
): BackendDynamicObjectRuntimeLayout | undefined {
  const representation = runtime?.representations.find((
    candidate,
  ): candidate is CompilerRuntimeDynamicObjectRepresentationIR =>
    candidate.kind === 'dynamic_object_representation'
  );
  if (!representation) {
    return undefined;
  }
  return {
    keyArrayWatTypeId: `${sanitizeWatIdentifier(representation.name)}_key_array`,
    representation,
    taggedValueArrayWatTypeId: `${sanitizeWatIdentifier(representation.name)}_tagged_value_array`,
    watTypeId: sanitizeWatIdentifier(representation.name),
  };
}

function createFallbackPropertyKeyIds(
  runtime?: CompilerRuntimeIR,
  functions: readonly CompilerFunctionIR[] = [],
): Map<string, number> {
  const keys = new Set<string>();
  for (const representation of runtime?.representations ?? []) {
    if (representation.kind === 'fallback_object_representation') {
      for (const key of representation.prototypeMembership.inheritedPropertyKeys) {
        keys.add(key);
      }
    } else if (representation.kind === 'specialized_object_representation') {
      for (const field of representation.fields) {
        keys.add(field.name);
      }
    }
  }
  for (const runtimeFunction of runtime?.functions ?? []) {
    for (const operation of runtimeFunction.operations) {
      switch (operation.kind) {
        case 'allocate_fallback_object':
          for (const entry of operation.entries) {
            keys.add(entry.key);
          }
          break;
        case 'get_fallback_object_property':
        case 'has_fallback_object_property':
        case 'set_fallback_object_property':
          keys.add(operation.propertyKey);
          break;
        case 'adapt_value':
          if (operation.family === 'object') {
            for (const entry of operation.fallbackMaterialization?.entries ?? []) {
              keys.add(entry.key);
            }
          }
          break;
      }
    }
  }
  for (const func of functions) {
    visitFunctionFallbackObjectBoundaryFields(func, (field) => {
      keys.add(field.name);
    });
  }
  return new Map(
    [...keys]
      .sort((left, right) => left.localeCompare(right))
      .map((key, index) => [key, index + 1]),
  );
}

function createStringLiteralIds(module?: CompilerModuleIR): Map<string, number> {
  return new Map((module?.stringLiterals ?? []).map((literal, index) => [literal, index]));
}

function getRequiredStringLiteralId(
  stringLiteralIdsByText: ReadonlyMap<string, number>,
  text: string,
): number {
  const literalId = stringLiteralIdsByText.get(text);
  if (literalId === undefined) {
    throw new Error(`Missing owned string literal id for "${text}".`);
  }
  return literalId;
}

function getPromiseFulfilledHandlerClosureSignature(
  module: CompilerModuleIR,
): CompilerClosureSignatureIR | undefined {
  return module.closureSignatures?.find((signature) =>
    signature.params.length === 1 &&
    signature.params[0] === 'tagged_ref' &&
    signature.resultType === 'tagged_ref' &&
    signature.sourceParamClassConstructorTagIds === undefined &&
    signature.paramClosureSignatureIds === undefined &&
    signature.paramTaggedPrimitiveKinds?.length === 1 &&
    signature.paramTaggedPrimitiveKinds[0]?.includesBoolean === true &&
    signature.paramTaggedPrimitiveKinds[0]?.includesNull === true &&
    signature.paramTaggedPrimitiveKinds[0]?.includesNumber === true &&
    signature.paramTaggedPrimitiveKinds[0]?.includesString === true &&
    signature.paramTaggedPrimitiveKinds[0]?.includesUndefined === true &&
    signature.paramHeapRepresentations?.length === 1 &&
    signature.paramHeapRepresentations[0]?.kind === 'dynamic_object_representation' &&
    signature.paramHeapArrayRepresentations === undefined &&
    signature.resultClassConstructorTagId === undefined &&
    signature.resultClosureSignatureId === undefined &&
    signature.resultTaggedPrimitiveKinds?.includesBoolean === true &&
    signature.resultTaggedPrimitiveKinds?.includesNull === true &&
    signature.resultTaggedPrimitiveKinds?.includesNumber === true &&
    signature.resultTaggedPrimitiveKinds?.includesString === true &&
    signature.resultTaggedPrimitiveKinds?.includesUndefined === true &&
    signature.resultHeapRepresentation === undefined &&
    signature.resultHeapArrayRepresentation === undefined
  );
}

