interface HostPromiseValueBridgeSpec {
  id: number;
  key: string;
  valueBoundary: CompilerHostBoundaryIR;
}

function getHostPromiseToInternalImportName(bridgeId?: number): string {
  return bridgeId === undefined
    ? SOUNDSCRIPT_HOST_PROMISE_TO_INTERNAL_IMPORT_NAME
    : `$host_promise_to_internal_${bridgeId}`;
}

function getHostPromiseToInternalImportExportName(bridgeId?: number): string {
  return bridgeId === undefined ? 'to_internal' : `to_internal_bridge_${bridgeId}`;
}

function getHostPromiseBridgeFulfillExportName(bridgeId?: number): string {
  return bridgeId === undefined
    ? SOUNDSCRIPT_PROMISE_BRIDGE_FULFILL_EXPORT_NAME
    : `__soundscript_promise_bridge_fulfill_${bridgeId}`;
}

function encodeHostBoundaryBridgeKey(boundary: CompilerHostBoundaryIR): string {
  switch (boundary.kind) {
    case 'scalar':
      return `scalar:${boundary.valueType}`;
    case 'string':
      return `string:${boundary.owned ? 'owned' : 'borrowed'}`;
    case 'closure':
      return `closure:${boundary.signatureId}`;
    case 'class_constructor':
      return `class:${boundary.classTagId}`;
    case 'externref':
      return 'externref';
    case 'object':
      return `object:${boundary.representation.kind}:${boundary.representation.name}:${
        (boundary.fields ?? []).map((field) =>
          `${field.name}:${field.optional ? 'optional' : 'required'}:${
            encodeHostBoundaryBridgeKey(field.boundary)
          }`
        ).join('|')
      }`;
    case 'tagged':
      return `tagged:${
        [
          boundary.includesBoolean ? 'b' : '',
          boundary.includesNull ? 'n' : '',
          boundary.includesNumber ? 'd' : '',
          boundary.includesString ? 's' : '',
          boundary.includesUndefined ? 'u' : '',
        ].join('')
      }:${boundary.heapBoundary ? encodeHostBoundaryBridgeKey(boundary.heapBoundary) : '-'}`;
    case 'promise':
      return `promise:${boundary.representation.kind}:${boundary.representation.name}:${
        boundary.valueBoundary ? encodeHostBoundaryBridgeKey(boundary.valueBoundary) : '-'
      }`;
    case 'array':
      return `array:${boundary.carrierType}:${
        encodeHostBoundaryBridgeKey(boundary.elementBoundary)
      }`;
    default: {
      const exhaustiveCheck: never = boundary;
      return exhaustiveCheck;
    }
  }
}

function hostPromiseValueBoundaryUsesGenericBridge(
  boundary: CompilerHostBoundaryIR | undefined,
): boolean {
  if (!boundary) {
    return true;
  }
  switch (boundary.kind) {
    case 'scalar':
    case 'string':
      return true;
    case 'tagged':
      return boundary.heapBoundary === undefined;
    default:
      return false;
  }
}

function collectTypedHostPromiseValueBridgeSpecs(
  module: CompilerModuleIR,
): HostPromiseValueBridgeSpec[] {
  const specsByKey = new Map<string, CompilerHostBoundaryIR>();
  const maybeAddBoundary = (boundary: CompilerHostBoundaryIR | undefined): void => {
    if (!boundary || hostPromiseValueBoundaryUsesGenericBridge(boundary)) {
      return;
    }
    const key = encodeHostBoundaryBridgeKey(boundary);
    if (!specsByKey.has(key)) {
      specsByKey.set(key, boundary);
    }
  };
  const maybeAddFiniteUnionPromiseBoundary = (
    boundary: CompilerUnionBoundaryIR | undefined,
  ): void => {
    for (const arm of boundary?.arms ?? []) {
      if (arm.kind === 'promise') {
        maybeAddBoundary(arm.boundary.valueBoundary);
      }
    }
  };
  for (const func of module.functions) {
    maybeAddBoundary(getHostPromiseBoundary(func.hostResultBoundary)?.valueBoundary);
    maybeAddFiniteUnionPromiseBoundary(func.hostUnionBoundaryResult);
    for (const paramBoundary of func.hostParamBoundaries ?? []) {
      maybeAddBoundary(getHostPromiseBoundary(paramBoundary.boundary)?.valueBoundary);
    }
    for (const param of func.hostUnionBoundaryParams ?? []) {
      maybeAddFiniteUnionPromiseBoundary(param.boundary);
    }
  }
  for (const signature of module.closureSignatures ?? []) {
    maybeAddBoundary(signature.resultPromiseValueBoundary);
    for (const boundary of signature.paramPromiseValueBoundaries ?? []) {
      maybeAddBoundary(boundary);
    }
  }
  return [...specsByKey.entries()]
    .sort(([left], [right]) => left.localeCompare(right))
    .map(([key, valueBoundary], index) => ({
      id: index,
      key,
      valueBoundary,
    }));
}

function getTypedHostPromiseValueBridgeSpec(
  module: CompilerModuleIR,
  boundary: CompilerHostBoundaryIR | undefined,
): HostPromiseValueBridgeSpec | undefined {
  if (!boundary || hostPromiseValueBoundaryUsesGenericBridge(boundary)) {
    return undefined;
  }
  const key = encodeHostBoundaryBridgeKey(boundary);
  return collectTypedHostPromiseValueBridgeSpecs(module).find((spec) => spec.key === key);
}

function getHostPromiseToInternalImportNameForBoundary(
  module: CompilerModuleIR,
  boundary: CompilerHostBoundaryIR | undefined,
): string {
  const spec = getTypedHostPromiseValueBridgeSpec(module, boundary);
  return getHostPromiseToInternalImportName(spec?.id);
}

function emitPromiseRuntimeImports(module: CompilerModuleIR): string[] {
  if (!moduleUsesHostPromiseBridge(module) && !moduleUsesAsyncGeneratorHostImportBridge(module)) {
    return [];
  }
  const typedPromiseValueBridgeSpecs = collectTypedHostPromiseValueBridgeSpecs(module);
  return [
    ...(moduleUsesAsyncGeneratorHostImportBridge(module) ||
        moduleUsesFiniteUnionPromiseBoundary(module)
      ? [
        `(import "soundscript_promise" "is_host" (func ${SOUNDSCRIPT_HOST_PROMISE_IS_HOST_IMPORT_NAME} (param externref) (result i32)))`,
      ]
      : []),
    `(import "soundscript_promise" "to_host" (func ${SOUNDSCRIPT_HOST_PROMISE_TO_HOST_IMPORT_NAME} (param (ref null eq)) (result externref)))`,
    `(import "soundscript_promise" "to_internal" (func ${SOUNDSCRIPT_HOST_PROMISE_TO_INTERNAL_IMPORT_NAME} (param externref) (param (ref null eq)) (result (ref null eq))))`,
    ...typedPromiseValueBridgeSpecs.map((spec) =>
      `(import "soundscript_promise" "${getHostPromiseToInternalImportExportName(spec.id)}" (func ${
        getHostPromiseToInternalImportName(spec.id)
      } (param externref) (param (ref null eq)) (result (ref null eq))))`
    ),
  ];
}

function emitAsyncGeneratorRuntimeImports(module: CompilerModuleIR): string[] {
  if (
    !moduleUsesAsyncGeneratorHostImportBridge(module) &&
    !moduleUsesAsyncGeneratorHostStepBridge(module) &&
    !moduleUsesAsyncGeneratorHostResultBridge(module)
  ) {
    return [];
  }
  return [
    ...(moduleUsesAsyncGeneratorHostImportBridge(module)
      ? [
        `(import "soundscript_async_generator" "to_step" (func ${SOUNDSCRIPT_HOST_ASYNC_GENERATOR_TO_STEP_IMPORT_NAME} (param externref) (result externref)))`,
        `(import "soundscript_async_generator" "to_internal" (func ${SOUNDSCRIPT_HOST_ASYNC_GENERATOR_TO_INTERNAL_IMPORT_NAME} (param externref) (param (ref null eq)) (result (ref null eq))))`,
      ]
      : []),
    `(import "soundscript_async_generator" "step" (func ${SOUNDSCRIPT_HOST_ASYNC_GENERATOR_STEP_IMPORT_NAME} (param externref) (param f64) (param externref) (param (ref null eq))))`,
    ...(moduleUsesAsyncGeneratorHostResultBridge(module)
      ? [
        `(import "soundscript_async_generator" "wrap" (func ${SOUNDSCRIPT_HOST_ASYNC_GENERATOR_WRAP_IMPORT_NAME} (param externref) (result externref)))`,
      ]
      : []),
  ];
}

function emitSyncGeneratorRuntimeImports(module: CompilerModuleIR): string[] {
  if (
    !moduleUsesSyncGeneratorHostImportBridge(module) &&
    !moduleUsesSyncGeneratorHostResultBridge(module)
  ) {
    return [];
  }
  return [
    ...(moduleUsesSyncGeneratorHostImportBridge(module)
      ? [
        `(import "soundscript_generator" "to_step" (func ${SOUNDSCRIPT_HOST_SYNC_GENERATOR_TO_STEP_IMPORT_NAME} (param externref) (result externref)))`,
      ]
      : []),
    ...(moduleUsesSyncGeneratorHostResultBridge(module)
      ? [
        `(import "soundscript_generator" "wrap" (func ${SOUNDSCRIPT_HOST_SYNC_GENERATOR_WRAP_IMPORT_NAME} (param externref) (result externref)))`,
      ]
      : []),
  ];
}

const SOUNDSCRIPT_HOST_THROW_IMPORT_NAME = '$host_throw_value';
const SOUNDSCRIPT_THROW_TAGGED_HELPER_NAME = '__soundscript_throw_tagged';
const SOUNDSCRIPT_TRY_CATCH_TAGGED_HELPER_NAME = '__soundscript_try_catch_tagged';

function emitTaggedThrowRuntimeImports(module: CompilerModuleIR): string[] {
  if (!moduleUsesTaggedThrowRuntime(module)) {
    return [];
  }
  return [
    `(import "soundscript_throw" "throw" (func ${SOUNDSCRIPT_HOST_THROW_IMPORT_NAME} (param externref)))`,
  ];
}

function emitSyncTryCatchRuntimeImports(module: CompilerModuleIR): string[] {
  if (!moduleUsesSyncTryCatchRuntime(module)) {
    return [];
  }
  return [
    `(import "soundscript_throw" "try_tagged" (func ${SOUNDSCRIPT_HOST_TRY_TAGGED_IMPORT_NAME} (param externref) (result externref)))`,
    `(import "soundscript_throw" "try_result_threw" (func ${SOUNDSCRIPT_HOST_TRY_RESULT_THREW_IMPORT_NAME} (param externref) (result i32)))`,
    `(import "soundscript_throw" "try_result_value" (func ${SOUNDSCRIPT_HOST_TRY_RESULT_VALUE_IMPORT_NAME} (param externref) (result externref)))`,
  ];
}

function moduleNeedsTaggedValueRuntime(module: CompilerModuleIR): boolean {
  const specializedTaggedArrayFieldBoundaryUsage = getSpecializedTaggedArrayFieldBoundaryUsage(
    module,
  );
  return module.runtime?.representations.some((representation) =>
        representation.kind === 'tagged_value_representation'
      ) === true ||
    getTaggedHostBoundaryUsage(module).usesHostBoundary ||
    specializedTaggedArrayFieldBoundaryUsage.usesParamBoundary ||
    specializedTaggedArrayFieldBoundaryUsage.usesResultBoundary ||
    moduleUsesTaggedNullRuntime(module) ||
    moduleUsesTaggedThrowRuntime(module) ||
    moduleUsesHostPromiseBridge(module) ||
    moduleUsesGeneratorStepClosureHostBridge(module) ||
    moduleUsesSyncTryCatchRuntime(module);
}

function emitTaggedValueType(module: CompilerModuleIR): string[] {
  return moduleNeedsTaggedValueRuntime(module)
    ? ['(type $tagged_value (struct (field i32) (field f64) (field (ref null eq))))']
    : [];
}

function emitTaggedValueHelpers(
  module: CompilerModuleIR,
  stringRuntimeLayout?: BackendStringRuntimeLayout,
): string[] {
  if (!moduleNeedsTaggedValueRuntime(module)) {
    return [];
  }
  const usesTaggedThrowRuntime = moduleUsesTaggedThrowRuntime(module);
  const usesAsyncGeneratorBridge = moduleUsesGeneratorStepClosureHostBridge(module);
  const usesNull = moduleUsesTaggedNullRuntime(module) || moduleUsesHostPromiseBridge(module) ||
    usesAsyncGeneratorBridge ||
    usesTaggedThrowRuntime ||
    moduleUsesSyncTryCatchRuntime(module);
  const taggedHostBoundaryUsage = getTaggedHostBoundaryUsage(module);
  const usesHostFallbackObjectBoundary = moduleUsesHostFallbackObjectBoundary(module);
  const usesHostPromiseParamBoundary = moduleUsesHostPromiseParamBridge(module) ||
    usesAsyncGeneratorBridge;
  const usesHostPromiseResultBoundary = moduleUsesHostPromiseResultBridge(module) ||
    usesAsyncGeneratorBridge;
  const specializedTaggedArrayFieldBoundaryUsage = getSpecializedTaggedArrayFieldBoundaryUsage(
    module,
  );
  const usesTaggedArrayHostStringBoundary =
    module.functions.some((func) =>
      [...getEffectiveHostTaggedArrayParamsByName(func).values()].some((param) =>
        param.includesString === true
      ) ||
      getEffectiveHostTaggedArrayResultKinds(func)?.includesString === true
    ) || specializedTaggedArrayFieldBoundaryUsage.usesParamStringBoundary ||
    specializedTaggedArrayFieldBoundaryUsage.usesResultStringBoundary;
  const usesTaggedArrayHostResultStringBoundary =
    module.functions.some((func) =>
      getEffectiveHostTaggedArrayResultKinds(func)?.includesString === true
    ) ||
    specializedTaggedArrayFieldBoundaryUsage.usesResultStringBoundary;
  const usesTaggedPrimitiveHostStringBoundary = taggedHostBoundaryUsage.usesStringBoundary ||
    usesHostFallbackObjectBoundary ||
    usesHostPromiseParamBoundary ||
    usesHostPromiseResultBoundary ||
    usesTaggedThrowRuntime ||
    moduleUsesSyncTryCatchRuntime(module);
  const usesTaggedPrimitiveHostResultStringBoundary =
    taggedHostBoundaryUsage.usesResultStringBoundary || usesHostFallbackObjectBoundary ||
    usesHostPromiseResultBoundary ||
    usesTaggedThrowRuntime ||
    moduleUsesSyncTryCatchRuntime(module);
  const usesTaggedString = moduleUsesTaggedStringRuntime(module) ||
    usesTaggedPrimitiveHostStringBoundary ||
    usesTaggedArrayHostStringBoundary;
  const usesTaggedStringHostExport = usesTaggedPrimitiveHostResultStringBoundary ||
    usesTaggedArrayHostResultStringBoundary;
  return [
    '(func $tag_undefined (result (ref null $tagged_value))',
    `${indent(1)}i32.const 0`,
    `${indent(1)}f64.const 0`,
    `${indent(1)}ref.null eq`,
    `${indent(1)}struct.new $tagged_value`,
    ')',
    ...(usesNull
      ? [
        '(func $tag_null (result (ref null $tagged_value))',
        `${indent(1)}i32.const 6`,
        `${indent(1)}f64.const 0`,
        `${indent(1)}ref.null eq`,
        `${indent(1)}struct.new $tagged_value`,
        ')',
      ]
      : []),
    '(func $tag_number (param $value f64) (result (ref null $tagged_value))',
    `${indent(1)}i32.const 2`,
    `${indent(1)}local.get $value`,
    `${indent(1)}ref.null eq`,
    `${indent(1)}struct.new $tagged_value`,
    ')',
    '(func $tag_boolean (param $value i32) (result (ref null $tagged_value))',
    `${indent(1)}i32.const 1`,
    `${indent(1)}local.get $value`,
    `${indent(1)}f64.convert_i32_s`,
    `${indent(1)}ref.null eq`,
    `${indent(1)}struct.new $tagged_value`,
    ')',
    ...(usesTaggedString && stringRuntimeLayout
      ? [
        `(func $tag_string (param $value (ref null $${stringRuntimeLayout.runtimeWatTypeId})) (result (ref null $tagged_value))`,
        `${indent(1)}i32.const 3`,
        `${indent(1)}f64.const 0`,
        `${indent(1)}local.get $value`,
        `${indent(1)}struct.new $tagged_value`,
        ')',
      ]
      : []),
    ...(moduleUsesSymbolRuntime(module)
      ? [
        '(func $tag_symbol (param $value (ref null $symbol_runtime)) (result (ref null $tagged_value))',
        `${indent(1)}i32.const 5`,
        `${indent(1)}f64.const 0`,
        `${indent(1)}local.get $value`,
        `${indent(1)}struct.new $tagged_value`,
        ')',
        '(func $untag_symbol (param $value (ref null $tagged_value)) (result (ref null $symbol_runtime))',
        `${indent(1)}local.get $value`,
        `${indent(1)}struct.get $tagged_value 2`,
        `${indent(1)}ref.cast (ref null $symbol_runtime)`,
        ')',
      ]
      : []),
    ...(moduleUsesBigIntRuntime(module)
      ? [
        '(func $tag_bigint (param $value (ref null $bigint_runtime)) (result (ref null $tagged_value))',
        `${indent(1)}i32.const 7`,
        `${indent(1)}f64.const 0`,
        `${indent(1)}local.get $value`,
        `${indent(1)}struct.new $tagged_value`,
        ')',
        '(func $untag_bigint (param $value (ref null $tagged_value)) (result (ref null $bigint_runtime))',
        `${indent(1)}local.get $value`,
        `${indent(1)}struct.get $tagged_value 2`,
        `${indent(1)}ref.cast (ref null $bigint_runtime)`,
        ')',
      ]
      : []),
    '(func $tag_heap_object (param $value (ref null eq)) (result (ref null $tagged_value))',
    `${indent(1)}i32.const 4`,
    `${indent(1)}f64.const 0`,
    `${indent(1)}local.get $value`,
    `${indent(1)}struct.new $tagged_value`,
    ')',
    '(func $untag_number (param $value (ref null $tagged_value)) (result f64)',
    `${indent(1)}local.get $value`,
    `${indent(1)}struct.get $tagged_value 1`,
    ')',
    '(func $untag_boolean (param $value (ref null $tagged_value)) (result i32)',
    `${indent(1)}local.get $value`,
    `${indent(1)}struct.get $tagged_value 1`,
    `${indent(1)}i32.trunc_f64_s`,
    ')',
    ...((usesTaggedString || usesTaggedStringHostExport) && stringRuntimeLayout
      ? [
        `(func $untag_owned_string (param $value (ref null $tagged_value)) (result (ref null $${stringRuntimeLayout.runtimeWatTypeId}))`,
        `${indent(1)}local.get $value`,
        `${indent(1)}struct.get $tagged_value 2`,
        `${indent(1)}ref.cast (ref null $${stringRuntimeLayout.runtimeWatTypeId})`,
        ')',
      ]
      : []),
    '(func $untag_heap_object (param $value (ref null $tagged_value)) (result (ref null eq))',
    `${indent(1)}local.get $value`,
    `${indent(1)}struct.get $tagged_value 2`,
    ')',
  ];
}

