function emitFallbackObjectTypes(layout?: BackendFallbackObjectRuntimeLayout): string[] {
  if (!layout) {
    return [];
  }
  return [
    `(type $${layout.occupancyArrayWatTypeId} (array (mut i32)))`,
    `(type $${layout.propertyKeyArrayWatTypeId} (array (mut i32)))`,
    `(type $${layout.taggedValueArrayWatTypeId} (array (mut (ref null $tagged_value))))`,
    `(type $${layout.watTypeId} (struct (field (mut i32)) (field (mut i32)) (field (mut i32)) (field (mut i32)) (field (mut (ref null $${layout.occupancyArrayWatTypeId}))) (field (mut (ref null $${layout.propertyKeyArrayWatTypeId}))) (field (mut (ref null $${layout.taggedValueArrayWatTypeId})))))`,
  ];
}

