function emitDynamicObjectValuesHelper(
  layout: BackendDynamicObjectRuntimeLayout,
  resultType: CompilerRuntimeListDynamicObjectValuesIR['resultType'],
): string[] {
  const helperName = getDynamicObjectValuesHelperName(resultType);
  const resultStructWatType = resultType === 'owned_array_ref'
    ? 'owned_string_array'
    : resultType === 'owned_number_array_ref'
    ? 'owned_number_array'
    : resultType === 'owned_boolean_array_ref'
    ? 'owned_boolean_array'
    : 'owned_tagged_array';
  const resultDataWatType = resultType === 'owned_array_ref'
    ? 'owned_string_array_data'
    : resultType === 'owned_number_array_ref'
    ? 'owned_number_array_data'
    : resultType === 'owned_boolean_array_ref'
    ? 'owned_boolean_array_data'
    : 'owned_tagged_array_data';
  const emitValueWriteLines = (
    level: number,
    storageIndexLocalName: string,
    resultIndexLocalName: string,
  ): string[] => [
    `${indent(level)}local.get $result_data`,
    `${indent(level)}local.get ${resultIndexLocalName}`,
    `${indent(level)}local.get $object`,
    `${indent(level)}struct.get $${layout.watTypeId} 3`,
    `${indent(level)}local.get ${storageIndexLocalName}`,
    `${indent(level)}array.get $${layout.taggedValueArrayWatTypeId}`,
    ...(resultType === 'owned_array_ref'
      ? [`${indent(level)}call $untag_owned_string`]
      : resultType === 'owned_number_array_ref'
      ? [`${indent(level)}call $untag_number`]
      : resultType === 'owned_boolean_array_ref'
      ? [`${indent(level)}call $untag_boolean`]
      : []),
    `${indent(level)}array.set $${resultDataWatType}`,
  ];

  return [
    `(func $${helperName} (param $object (ref null $${layout.watTypeId})) (result (ref null $${resultStructWatType}))`,
    `${indent(1)}(local $size i32)`,
    `${indent(1)}(local $result_data (ref null $${resultDataWatType}))`,
    `${indent(1)}(local $result (ref null $${resultStructWatType}))`,
    ...emitDynamicObjectOrderedEnumerationLocals(),
    `${indent(1)}local.get $object`,
    `${indent(1)}struct.get $${layout.watTypeId} 0`,
    `${indent(1)}local.set $size`,
    `${indent(1)}local.get $size`,
    `${indent(1)}array.new_default $${resultDataWatType}`,
    `${indent(1)}local.set $result_data`,
    `${indent(1)}local.get $result_data`,
    `${indent(1)}struct.new $${resultStructWatType}`,
    `${indent(1)}local.set $result`,
    ...emitDynamicObjectOrderedEnumerationBody(layout, emitValueWriteLines),
    `${indent(1)}local.get $result`,
    ')',
  ];
}

function emitDynamicObjectEntriesHelper(
  layout: BackendDynamicObjectRuntimeLayout,
  pairValueType: CompilerRuntimeListDynamicObjectEntriesIR['pairValueType'],
): string[] {
  const helperName = getDynamicObjectEntriesHelperName(pairValueType);
  const pairArrayDataWatType = pairValueType === 'owned_string_ref'
    ? 'owned_string_array_data'
    : 'owned_tagged_array_data';
  const pairArrayWatType = pairValueType === 'owned_string_ref'
    ? 'owned_string_array'
    : 'owned_tagged_array';
  const emitPairWriteLines = (
    level: number,
    storageIndexLocalName: string,
    resultIndexLocalName: string,
  ): string[] => [
    `${indent(level)}local.get $result_data`,
    `${indent(level)}local.get ${resultIndexLocalName}`,
    ...(pairValueType === 'owned_string_ref'
      ? [
        `${indent(level)}local.get $object`,
        `${indent(level)}struct.get $${layout.watTypeId} 2`,
        `${indent(level)}local.get ${storageIndexLocalName}`,
        `${indent(level)}array.get $${layout.keyArrayWatTypeId}`,
        `${indent(level)}local.get $object`,
        `${indent(level)}struct.get $${layout.watTypeId} 3`,
        `${indent(level)}local.get ${storageIndexLocalName}`,
        `${indent(level)}array.get $${layout.taggedValueArrayWatTypeId}`,
        `${indent(level)}call $untag_owned_string`,
        `${indent(level)}array.new_fixed $${pairArrayDataWatType} 2`,
        `${indent(level)}struct.new $${pairArrayWatType}`,
      ]
      : [
        `${indent(level)}local.get $object`,
        `${indent(level)}struct.get $${layout.watTypeId} 2`,
        `${indent(level)}local.get ${storageIndexLocalName}`,
        `${indent(level)}array.get $${layout.keyArrayWatTypeId}`,
        `${indent(level)}call $tag_string`,
        `${indent(level)}local.get $object`,
        `${indent(level)}struct.get $${layout.watTypeId} 3`,
        `${indent(level)}local.get ${storageIndexLocalName}`,
        `${indent(level)}array.get $${layout.taggedValueArrayWatTypeId}`,
        `${indent(level)}array.new_fixed $${pairArrayDataWatType} 2`,
        `${indent(level)}struct.new $${pairArrayWatType}`,
      ]),
    `${indent(level)}array.set $owned_heap_array_data`,
  ];

  return [
    `(func $${helperName} (param $object (ref null $${layout.watTypeId})) (result (ref null $owned_heap_array))`,
    `${indent(1)}(local $size i32)`,
    `${indent(1)}(local $result_data (ref null $owned_heap_array_data))`,
    `${indent(1)}(local $result (ref null $owned_heap_array))`,
    ...emitDynamicObjectOrderedEnumerationLocals(),
    `${indent(1)}local.get $object`,
    `${indent(1)}struct.get $${layout.watTypeId} 0`,
    `${indent(1)}local.set $size`,
    `${indent(1)}local.get $size`,
    `${indent(1)}array.new_default $owned_heap_array_data`,
    `${indent(1)}local.set $result_data`,
    `${indent(1)}local.get $result_data`,
    `${indent(1)}struct.new $owned_heap_array`,
    `${indent(1)}local.set $result`,
    ...emitDynamicObjectOrderedEnumerationBody(layout, emitPairWriteLines),
    `${indent(1)}local.get $result`,
    ')',
  ];
}

