function collectFieldReadOpsByResult(
  operations: readonly CompilerRuntimeFunctionIR['operations'][number][],
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
): Map<string, IndexedRuntimeOperation<CompilerRuntimeGetSpecializedObjectFieldIR>> {
  const fieldReadOpsByResult = new Map<
    string,
    IndexedRuntimeOperation<CompilerRuntimeGetSpecializedObjectFieldIR>
  >();
  operations.forEach((operation, index) => {
    if (operation.kind !== 'get_specialized_object_field') {
      return;
    }
    const layout = getLayoutForRepresentationName(
      operation.representation.name,
      layoutsByRepresentationName,
    );
    if (layout.fields[operation.fieldIndex] === undefined) {
      throw createUnsupportedHeapRuntimeBackendError(
        `Specialized object field index ${operation.fieldIndex} is out of bounds for ${operation.representation.name}.`,
      );
    }
    fieldReadOpsByResult.set(operation.resultName, { index, operation });
  });
  return fieldReadOpsByResult;
}

