function functionUsesOwnedBooleanArrayLiteralRuntime(func: CompilerFunctionIR): boolean {
  let usesOwnedBooleanArrayLiteral = false;
  const visitExpression = (expression: CompilerExpressionIR): void => {
    if (usesOwnedBooleanArrayLiteral) {
      return;
    }
    if (expression.kind === 'owned_boolean_array_literal') {
      usesOwnedBooleanArrayLiteral = true;
      return;
    }
    forEachExpressionChild(expression, visitExpression);
  };
  const visitStatements = (statements: readonly CompilerStatementIR[]): void => {
    for (const statement of statements) {
      if (usesOwnedBooleanArrayLiteral) {
        return;
      }
      switch (statement.kind) {
        case 'expression':
        case 'box_set':
        case 'global_set':
        case 'local_set':
        case 'return':
        case 'specialized_object_field_set':
          visitExpression(statement.value);
          break;
        case 'owned_heap_array_set':
        case 'owned_string_array_set':
        case 'owned_number_array_set':
        case 'owned_boolean_array_set':
        case 'owned_tagged_array_set':
          visitExpression(statement.array);
          visitExpression(statement.index);
          visitExpression(statement.value);
          break;
        case 'if':
          visitExpression(statement.condition);
          visitStatements(statement.thenBody);
          visitStatements(statement.elseBody);
          break;
        case 'while':
          visitExpression(statement.condition);
          visitStatements(statement.body);
          break;
      }
    }
  };
  visitStatements(func.body);
  return usesOwnedBooleanArrayLiteral;
}

function functionUsesOwnedTaggedArrayLiteralRuntime(func: CompilerFunctionIR): boolean {
  let usesOwnedTaggedArrayLiteral = false;
  const visitExpression = (expression: CompilerExpressionIR): void => {
    if (usesOwnedTaggedArrayLiteral) {
      return;
    }
    if (expression.kind === 'owned_tagged_array_literal') {
      usesOwnedTaggedArrayLiteral = true;
      return;
    }
    forEachExpressionChild(expression, visitExpression);
  };
  const visitStatements = (statements: readonly CompilerStatementIR[]): void => {
    for (const statement of statements) {
      if (usesOwnedTaggedArrayLiteral) {
        return;
      }
      switch (statement.kind) {
        case 'expression':
        case 'box_set':
        case 'global_set':
        case 'local_set':
        case 'return':
        case 'specialized_object_field_set':
          visitExpression(statement.value);
          break;
        case 'owned_heap_array_set':
        case 'owned_string_array_set':
        case 'owned_number_array_set':
        case 'owned_boolean_array_set':
        case 'owned_tagged_array_set':
          visitExpression(statement.array);
          visitExpression(statement.index);
          visitExpression(statement.value);
          break;
        case 'if':
          visitExpression(statement.condition);
          visitStatements(statement.thenBody);
          visitStatements(statement.elseBody);
          break;
        case 'while':
          visitExpression(statement.condition);
          visitStatements(statement.body);
          break;
      }
    }
  };
  visitStatements(func.body);
  return usesOwnedTaggedArrayLiteral;
}

function createFunctionBackendRuntimeContext(
  func: CompilerFunctionIR,
  functionsByName: ReadonlyMap<string, CompilerFunctionIR>,
  closureSignaturesById: ReadonlyMap<number, CompilerClosureSignatureIR>,
  runtime: CompilerRuntimeIR | undefined,
  layoutsByRepresentationName: ReadonlyMap<string, BackendSpecializedObjectLayout>,
  fallbackPropertyKeyIdsByKey: ReadonlyMap<string, number>,
  stringLiteralIdsByText: ReadonlyMap<string, number>,
  stringRuntimeLayout?: BackendStringRuntimeLayout,
): FunctionBackendRuntimeContext {
  const operations = getRuntimeOperationsForFunction(func, runtime);
  const hasHostFallbackBoundary = getHostFallbackObjectParamBoundaryNames(func).length > 0 ||
    hasHostFallbackObjectResultBoundary(func) ||
    getHostTaggedHeapNullableFallbackParamBoundaryNames(func).length > 0 ||
    hasHostTaggedHeapNullableFallbackResultBoundary(func);
  const callsFallbackParamBoundaryFunction = functionCallsFunctionWithHeapParamRepresentationKind(
    func,
    functionsByName,
    closureSignaturesById,
    'fallback_object_representation',
  );
  const fallbackObjectLayout = (
      functionUsesFallbackRuntime(func, operations) ||
      functionCallsFallbackReturningFunction(func, functionsByName) ||
      callsFallbackParamBoundaryFunction ||
      hasHostFallbackBoundary ||
      (func.heapLocalRepresentations ?? []).some((boundary) =>
        boundary.representation.kind === 'fallback_object_representation'
      ) ||
      getEffectiveFunctionHeapResultRepresentation(func)?.kind ===
        'fallback_object_representation'
    )
    ? getFallbackObjectLayout(runtime)
    : undefined;
  const callsDynamicParamBoundaryFunction = functionCallsFunctionWithHeapParamRepresentationKind(
    func,
    functionsByName,
    closureSignaturesById,
    'dynamic_object_representation',
  );
  const dynamicObjectLayout = (
      operations.some((operation) =>
        operation.kind === 'allocate_dynamic_object' ||
        operation.kind === 'clear_dynamic_object' ||
        operation.kind === 'copy_dynamic_object_entries' ||
        operation.kind === 'delete_dynamic_object_property' ||
        operation.kind === 'get_dynamic_object_property' ||
        operation.kind === 'get_dynamic_object_size' ||
        operation.kind === 'has_dynamic_object_property' ||
        operation.kind === 'list_dynamic_object_entries' ||
        operation.kind === 'list_dynamic_object_keys' ||
        operation.kind === 'list_dynamic_object_values' ||
        operation.kind === 'set_dynamic_object_property'
      ) ||
      callsDynamicParamBoundaryFunction ||
      [...getEffectiveFunctionHeapParamRepresentationsByName(func).values()].some((
        representation,
      ) => representation.kind === 'dynamic_object_representation') ||
      (func.heapLocalRepresentations ?? []).some((boundary) =>
        boundary.representation.kind === 'dynamic_object_representation'
      ) ||
      getEffectiveFunctionHeapResultRepresentation(func)?.kind ===
        'dynamic_object_representation' ||
      (func.hostUnionBoundaryParams ?? []).some((param) =>
        finiteUnionBoundaryHasGeneratorArm(param.boundary)
      ) ||
      finiteUnionBoundaryHasGeneratorArm(func.hostUnionBoundaryResult) ||
      statementsUseStringHelper(func.body, isPromiseRuntimeHelperCall)
    )
    ? getDynamicObjectLayout(runtime)
    : undefined;
  const heapLocalNames = new Set([
    ...func.params.filter((param) => param.type === 'heap_ref').map((param) => param.name),
    ...func.locals.filter((local) => local.type === 'heap_ref').map((local) => local.name),
  ]);
  const dynamicAllocationsByLocal = collectDynamicAllocationsByLocal(operations);
  const specializedAllocationsByLocal = collectSpecializedAllocationsByLocal(operations);
  const fallbackAllocationsByLocal = collectFallbackAllocationsByLocal(operations);
  const heapLocalRepresentations = inferHeapLocalRepresentations(
    func,
    operations,
    dynamicAllocationsByLocal,
    specializedAllocationsByLocal,
    fallbackAllocationsByLocal,
    layoutsByRepresentationName,
    fallbackObjectLayout,
    dynamicObjectLayout,
    functionsByName,
  );
  const specializedCallResultScratchLocalsByRepresentationName = new Map<string, string>();
  const usedScratchLocalNames = new Set<string>();
  const ensureSpecializedFallbackGeneralizationScratchLocal = (
    representationName: string,
  ): void => {
    if (specializedCallResultScratchLocalsByRepresentationName.has(representationName)) {
      return;
    }
    const baseScratchLocalName = `__fallback_generalize_${
      sanitizeWatIdentifier(representationName)
    }`;
    let scratchLocalName = baseScratchLocalName;
    let suffix = 1;
    while (usedScratchLocalNames.has(scratchLocalName)) {
      scratchLocalName = `${baseScratchLocalName}_${suffix}`;
      suffix += 1;
    }
    usedScratchLocalNames.add(scratchLocalName);
    specializedCallResultScratchLocalsByRepresentationName.set(
      representationName,
      scratchLocalName,
    );
  };
  let ownedHeapArrayScratchLocalName: string | undefined;
  if (functionUsesOwnedHeapArrayLiteralRuntime(func)) {
    const baseScratchLocalName = '__owned_heap_array_tmp';
    ownedHeapArrayScratchLocalName = baseScratchLocalName;
    let suffix = 1;
    while (usedScratchLocalNames.has(ownedHeapArrayScratchLocalName)) {
      ownedHeapArrayScratchLocalName = `${baseScratchLocalName}_${suffix}`;
      suffix += 1;
    }
    usedScratchLocalNames.add(ownedHeapArrayScratchLocalName);
  }
  let ownedArrayScratchLocalName: string | undefined;
  if (functionUsesOwnedStringArrayLiteralRuntime(func)) {
    const baseScratchLocalName = '__owned_array_tmp';
    ownedArrayScratchLocalName = baseScratchLocalName;
    let suffix = 1;
    while (usedScratchLocalNames.has(ownedArrayScratchLocalName)) {
      ownedArrayScratchLocalName = `${baseScratchLocalName}_${suffix}`;
      suffix += 1;
    }
    usedScratchLocalNames.add(ownedArrayScratchLocalName);
  }
  let ownedNumberArrayScratchLocalName: string | undefined;
  if (functionUsesOwnedNumberArrayLiteralRuntime(func)) {
    const baseScratchLocalName = '__owned_number_array_tmp';
    ownedNumberArrayScratchLocalName = baseScratchLocalName;
    let suffix = 1;
    while (usedScratchLocalNames.has(ownedNumberArrayScratchLocalName)) {
      ownedNumberArrayScratchLocalName = `${baseScratchLocalName}_${suffix}`;
      suffix += 1;
    }
    usedScratchLocalNames.add(ownedNumberArrayScratchLocalName);
  }
  let ownedBooleanArrayScratchLocalName: string | undefined;
  if (functionUsesOwnedBooleanArrayLiteralRuntime(func)) {
    const baseScratchLocalName = '__owned_boolean_array_tmp';
    ownedBooleanArrayScratchLocalName = baseScratchLocalName;
    let suffix = 1;
    while (usedScratchLocalNames.has(ownedBooleanArrayScratchLocalName)) {
      ownedBooleanArrayScratchLocalName = `${baseScratchLocalName}_${suffix}`;
      suffix += 1;
    }
    usedScratchLocalNames.add(ownedBooleanArrayScratchLocalName);
  }
  let ownedTaggedArrayScratchLocalName: string | undefined;
  if (functionUsesOwnedTaggedArrayLiteralRuntime(func)) {
    const baseScratchLocalName = '__owned_tagged_array_tmp';
    ownedTaggedArrayScratchLocalName = baseScratchLocalName;
    let suffix = 1;
    while (usedScratchLocalNames.has(ownedTaggedArrayScratchLocalName)) {
      ownedTaggedArrayScratchLocalName = `${baseScratchLocalName}_${suffix}`;
      suffix += 1;
    }
    usedScratchLocalNames.add(ownedTaggedArrayScratchLocalName);
  }
  const collectSpecializedCallResultScratchLocals = (
    statements: readonly CompilerStatementIR[],
  ): void => {
    statements.forEach((statement) => {
      switch (statement.kind) {
        case 'local_set': {
          if (
            statement.value.kind === 'call' &&
            statement.value.type === 'heap_ref' &&
            heapLocalRepresentations.get(statement.name)?.kind === 'fallback'
          ) {
            const callee = functionsByName.get(statement.value.callee);
            const resultRepresentation = callee
              ? getEffectiveFunctionHeapResultRepresentation(callee)
              : undefined;
            if (resultRepresentation?.kind === 'specialized_object_representation') {
              ensureSpecializedFallbackGeneralizationScratchLocal(resultRepresentation.name);
            }
          }
          if (
            statement.value.kind === 'heap_placeholder' &&
            heapLocalRepresentations.get(statement.name)?.kind === 'fallback'
          ) {
            for (const allocation of specializedAllocationsByLocal.get(statement.name) ?? []) {
              ensureSpecializedFallbackGeneralizationScratchLocal(
                allocation.operation.representation.name,
              );
            }
          }
          break;
        }
        case 'if':
          collectSpecializedCallResultScratchLocals(statement.thenBody);
          collectSpecializedCallResultScratchLocals(statement.elseBody);
          break;
        case 'while':
          collectSpecializedCallResultScratchLocals(statement.body);
          break;
      }
    });
  };
  collectSpecializedCallResultScratchLocals(func.body);
  if (fallbackObjectLayout) {
    for (const representation of heapLocalRepresentations.values()) {
      if (representation.kind === 'specialized') {
        ensureSpecializedFallbackGeneralizationScratchLocal(
          representation.layout.representation.name,
        );
      }
    }
  }
  return {
    boxedHeapRepresentations: new Map<string, BackendHeapRepresentation>(),
    closureSignaturesById,
    consumedOperationIndexes: new Set<number>(),
    currentFunction: func,
    dynamicAllocationOpIndexesByLocal: new Map<string, number>(),
    dynamicAllocationsByLocal,
    dynamicObjectClearOpsByResult: collectDynamicObjectClearOpsByResult(operations),
    dynamicObjectEntryListingOpsByResult: collectDynamicObjectEntryListingOpsByResult(operations),
    dynamicObjectKeyListingOpsByResult: collectDynamicObjectKeyListingOpsByResult(operations),
    dynamicObjectLayout,
    dynamicObjectSizeOpsByResult: collectDynamicObjectSizeOpsByResult(operations),
    dynamicObjectValueListingOpsByResult: collectDynamicObjectValueListingOpsByResult(operations),
    dynamicPropertyDeleteOpsByResult: collectDynamicPropertyDeleteOpsByResult(operations),
    dynamicPropertyHasOpsByResult: collectDynamicPropertyHasOpsByResult(operations),
    dynamicPropertyReadOpsByResult: collectDynamicPropertyReadOpsByResult(operations),
    fallbackAllocationOpIndexesByLocal: new Map<string, number>(),
    fallbackAllocationsByLocal,
    fallbackObjectLayout,
    fallbackObjectKeyListingOpsByResult: collectFallbackObjectKeyListingOpsByResult(operations),
    fallbackPropertyHasOpsByResult: collectFallbackPropertyHasOpsByResult(operations),
    fallbackPropertyKeyIdsByKey,
    fallbackScratchLocalName: fallbackObjectLayout ? '__fallback_tmp' : undefined,
    fallbackPropertyReadOpsByResult: collectFallbackPropertyReadOpsByResult(operations),
    fieldReadOpsByResult: collectFieldReadOpsByResult(operations, layoutsByRepresentationName),
    functionsByName,
    heapLocalRepresentations,
    heapLocalNames,
    initializedLocalNames: new Set(func.params.map((param) => param.name)),
    layoutsByRepresentationName,
    ownedHeapArrayScratchLocalName,
    ownedArrayScratchLocalName,
    ownedNumberArrayScratchLocalName,
    ownedBooleanArrayScratchLocalName,
    ownedTaggedArrayScratchLocalName,
    nextSequentialOperationIndex: 0,
    stringLiteralIdsByText,
    stringRuntimeLayout,
    operations,
    specializedAllocationOpIndexesByLocal: new Map<string, number>(),
    specializedAllocationsByLocal,
    specializedCallResultScratchLocalsByRepresentationName,
    specializedObjectKeyListingOpsByResult: collectSpecializedObjectKeyListingOpsByResult(
      operations,
    ),
    specializedOwnPropertyHasOpsByResult: collectSpecializedOwnPropertyHasOpsByResult(
      operations,
      layoutsByRepresentationName,
    ),
    valueTypesByName: new Map(
      [...func.params, ...func.locals].map((local) => [local.name, local.type]),
    ),
  };
}

function getHeapLocalWatType(
  localName: string,
  runtime: FunctionBackendRuntimeContext,
): string {
  const representation = runtime.heapLocalRepresentations.get(localName);
  if (!representation) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Missing heap representation for local ${localName}.`,
    );
  }
  return `(ref null $${representation.layout.watTypeId})`;
}

function getHeapParamRepresentationWatType(
  representation: CompilerRuntimeRepresentationRefIR<'object'>,
  runtime: FunctionBackendRuntimeContext,
): string {
  switch (representation.kind) {
    case 'fallback_object_representation':
      if (!runtime.fallbackObjectLayout) {
        throw createUnsupportedHeapRuntimeBackendError(
          'Missing fallback object layout for heap param cast.',
        );
      }
      return `(ref null $${runtime.fallbackObjectLayout.watTypeId})`;
    case 'dynamic_object_representation':
      if (!runtime.dynamicObjectLayout) {
        throw createUnsupportedHeapRuntimeBackendError(
          'Missing dynamic object layout for heap param cast.',
        );
      }
      return `(ref null $${runtime.dynamicObjectLayout.watTypeId})`;
    case 'specialized_object_representation':
      return getHeapBoundaryWatType(representation.name, runtime);
  }
}

function getRuntimeHeapRepresentationForExpression(
  expression: CompilerExpressionIR,
  runtime: FunctionBackendRuntimeContext,
): BackendHeapRepresentation | undefined {
  switch (expression.kind) {
    case 'local_get':
      return expression.type === 'heap_ref'
        ? runtime.heapLocalRepresentations.get(expression.name)
        : undefined;
    case 'box_get':
      return expression.type === 'heap_ref' && expression.box.kind === 'local_get'
        ? runtime.boxedHeapRepresentations.get(expression.box.name)
        : undefined;
    case 'untag_heap_object':
      return expression.type === 'heap_ref' && expression.heapRepresentation
        ? getHeapRepresentationForBoundary(
          expression.heapRepresentation,
          runtime.layoutsByRepresentationName,
          runtime.fallbackObjectLayout,
          runtime.dynamicObjectLayout,
        )
        : undefined;
    case 'class_static_field_get':
      return expression.type === 'heap_ref' && expression.heapRepresentation
        ? getHeapRepresentationForBoundary(
          expression.heapRepresentation,
          runtime.layoutsByRepresentationName,
          runtime.fallbackObjectLayout,
          runtime.dynamicObjectLayout,
        )
        : undefined;
    case 'call': {
      if (expression.type !== 'heap_ref') {
        return undefined;
      }
      if (
        expression.callee === '__soundscript_promise_new_pending' ||
        expression.callee === '__soundscript_promise_resolve' ||
        expression.callee === '__soundscript_promise_reject' ||
        expression.callee === '__soundscript_promise_then' ||
        expression.callee === SOUNDSCRIPT_ASYNC_GENERATOR_STEP_HELPER_NAME
      ) {
        return runtime.dynamicObjectLayout
          ? {
            kind: 'dynamic',
            layout: runtime.dynamicObjectLayout,
          }
          : undefined;
      }
      const callee = runtime.functionsByName.get(expression.callee);
      const resultRepresentation = callee
        ? getEffectiveFunctionHeapResultRepresentation(callee)
        : undefined;
      return resultRepresentation
        ? getHeapRepresentationForBoundary(
          resultRepresentation,
          runtime.layoutsByRepresentationName,
          runtime.fallbackObjectLayout,
          runtime.dynamicObjectLayout,
        )
        : undefined;
    }
    case 'closure_call': {
      if (expression.type !== 'heap_ref') {
        return undefined;
      }
      const signature = runtime.closureSignaturesById.get(expression.signatureId);
      if (signature?.resultPromiseValueBoundary) {
        return runtime.dynamicObjectLayout
          ? {
            kind: 'dynamic',
            layout: runtime.dynamicObjectLayout,
          }
          : undefined;
      }
      return signature?.resultHeapRepresentation
        ? getHeapRepresentationForBoundary(
          signature.resultHeapRepresentation,
          runtime.layoutsByRepresentationName,
          runtime.fallbackObjectLayout,
          runtime.dynamicObjectLayout,
        )
        : undefined;
    }
    default:
      return undefined;
  }
}

function getNextSpecializedAllocationOp(
  localName: string,
  runtime: FunctionBackendRuntimeContext,
): IndexedRuntimeOperation<CompilerRuntimeAllocateSpecializedObjectIR> {
  const nextAllocationIndex = runtime.specializedAllocationOpIndexesByLocal.get(localName) ?? 0;
  const allocation = runtime.specializedAllocationsByLocal.get(localName)?.[nextAllocationIndex];
  if (!allocation) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Missing specialized object allocation op for heap local ${localName}.`,
    );
  }
  runtime.specializedAllocationOpIndexesByLocal.set(localName, nextAllocationIndex + 1);
  return allocation;
}

function getNextFallbackAllocationOp(
  localName: string,
  runtime: FunctionBackendRuntimeContext,
): IndexedRuntimeOperation<CompilerRuntimeAllocateFallbackObjectIR> {
  const nextAllocationIndex = runtime.fallbackAllocationOpIndexesByLocal.get(localName) ?? 0;
  const allocation = runtime.fallbackAllocationsByLocal.get(localName)?.[nextAllocationIndex];
  if (!allocation) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Missing fallback object allocation op for heap local ${localName}.`,
    );
  }
  runtime.fallbackAllocationOpIndexesByLocal.set(localName, nextAllocationIndex + 1);
  return allocation;
}

function getNextDynamicAllocationOp(
  localName: string,
  runtime: FunctionBackendRuntimeContext,
): IndexedRuntimeOperation<CompilerRuntimeAllocateDynamicObjectIR> {
  const nextAllocationIndex = runtime.dynamicAllocationOpIndexesByLocal.get(localName) ?? 0;
  const allocation = runtime.dynamicAllocationsByLocal.get(localName)?.[nextAllocationIndex];
  if (!allocation) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Missing dynamic object allocation op for heap local ${localName}.`,
    );
  }
  runtime.dynamicAllocationOpIndexesByLocal.set(localName, nextAllocationIndex + 1);
  return allocation;
}

function markOperationConsumed(index: number, runtime: FunctionBackendRuntimeContext): void {
  runtime.consumedOperationIndexes.add(index);
  while (runtime.consumedOperationIndexes.has(runtime.nextSequentialOperationIndex)) {
    runtime.nextSequentialOperationIndex += 1;
  }
}

function getLocalValueType(
  name: string,
  runtime: FunctionBackendRuntimeContext,
): CompilerValueType {
  const valueType = runtime.valueTypesByName.get(name);
  if (!valueType) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Missing value type metadata for local ${name}.`,
    );
  }
  return valueType;
}

