function emitSpecializedFieldReadOp(
  fieldRead: IndexedRuntimeOperation<CompilerRuntimeGetSpecializedObjectFieldIR>,
  resultType: CompilerValueType,
  level: number,
  runtime: FunctionBackendRuntimeContext,
): string[] {
  markOperationConsumed(fieldRead.index, runtime);
  const layout = getLayoutForRepresentationName(
    fieldRead.operation.representation.name,
    runtime.layoutsByRepresentationName,
  );
  const field = layout.fields[fieldRead.operation.fieldIndex];
  if (!field) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Specialized object field index ${fieldRead.operation.fieldIndex} is out of bounds for ${fieldRead.operation.representation.name}.`,
    );
  }
  const lines = [
    `${indent(level)}local.get $${fieldRead.operation.objectName}`,
    `${indent(level)}struct.get $${layout.watTypeId} ${
      getSpecializedObjectFieldSlotIndex(layout, fieldRead.operation.fieldIndex)
    }`,
  ];
  if (field.valueType === 'closure_ref' && resultType === 'closure_ref') {
    return fieldRead.operation.closureSignatureId !== undefined
      ? [
        `${indent(level)}local.get $${fieldRead.operation.objectName}`,
        `${indent(level)}call $${getHostObjectLookupCachedImportFunctionName()}`,
        `${indent(level)}ref.is_null`,
        `${indent(level)}(if (result (ref null $closure))`,
        `${indent(level + 1)}(then`,
        ...lines.map((line) => `${indent(1)}${line}`),
        `${indent(level + 1)})`,
        `${indent(level + 1)}(else`,
        `${indent(level + 2)}local.get $${fieldRead.operation.objectName}`,
        `${indent(level + 2)}call $${getHostObjectLookupCachedImportFunctionName()}`,
        `${indent(level + 2)}call $${getHostObjectImportFunctionName('get_closure', field.name)}`,
        `${
          indent(level + 2)
        }call $host_externref_to_closure_${fieldRead.operation.closureSignatureId}`,
        `${indent(level + 1)})`,
        `${indent(level)})`,
      ]
      : lines;
  }
  if (field.valueType === 'heap_ref' && resultType === 'heap_ref') {
    const resultRepresentation = getHeapRepresentationForLocal(
      fieldRead.operation.resultName,
      runtime,
    );
    return [
      ...lines,
      `${indent(level)}ref.cast (ref null $${resultRepresentation.layout.watTypeId})`,
    ];
  }
  if (field.valueType === resultType) {
    return lines;
  }
  if (field.valueType === 'tagged_ref') {
    switch (resultType) {
      case 'f64':
        return [...lines, `${indent(level)}call $untag_number`];
      case 'i32':
        return [...lines, `${indent(level)}call $untag_boolean`];
      case 'tagged_ref':
        return lines;
      case 'heap_ref': {
        const resultRepresentation = getHeapRepresentationForLocal(
          fieldRead.operation.resultName,
          runtime,
        );
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $${resultRepresentation.layout.watTypeId})`,
        ];
      }
      case 'class_constructor_ref':
        return [...lines, `${indent(level)}call $untag_heap_object`];
      case 'string_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_owned_string`,
          `${indent(level)}call $owned_string_to_host`,
        ];
      case 'owned_string_ref':
        return [...lines, `${indent(level)}call $untag_owned_string`];
      case 'owned_array_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $owned_string_array)`,
        ];
      case 'owned_number_array_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $owned_number_array)`,
        ];
      case 'owned_boolean_array_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $owned_boolean_array)`,
        ];
      case 'owned_tagged_array_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $owned_tagged_array)`,
        ];
      case 'owned_heap_array_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $owned_heap_array)`,
        ];
      case 'closure_ref':
        return [
          ...lines,
          `${indent(level)}call $untag_heap_object`,
          `${indent(level)}ref.cast (ref null $closure)`,
        ];
      case 'box_ref':
        return [...lines, `${indent(level)}call $untag_heap_object`];
      case 'symbol_ref':
        throw createUnsupportedHeapRuntimeBackendError(
          'Symbol-valued specialized object reads are not supported.',
        );
      case 'bigint_ref':
        throw createUnsupportedHeapRuntimeBackendError(
          'BigInt-valued specialized object reads are not supported.',
        );
      default: {
        const exhaustiveCheck: never = resultType;
        return exhaustiveCheck;
      }
    }
  }
  if (resultType === 'heap_ref') {
    const resultRepresentation = getHeapRepresentationForLocal(
      fieldRead.operation.resultName,
      runtime,
    );
    return [
      ...lines,
      `${indent(level)}ref.cast (ref null $${resultRepresentation.layout.watTypeId})`,
    ];
  }
  return lines;
}

function emitSpecializedOwnPropertyHasOp(
  propertyHas: IndexedRuntimeOperation<CompilerRuntimeHasSpecializedObjectOwnPropertyIR>,
  level: number,
  runtime: FunctionBackendRuntimeContext,
): string[] {
  markOperationConsumed(propertyHas.index, runtime);
  const layout = getLayoutForRepresentationName(
    propertyHas.operation.representation.name,
    runtime.layoutsByRepresentationName,
  );
  const field = layout.fields[propertyHas.operation.fieldIndex];
  if (!field) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Specialized object field index ${propertyHas.operation.fieldIndex} is out of bounds for ${propertyHas.operation.representation.name}.`,
    );
  }
  if (field.optional) {
    throw createUnsupportedHeapRuntimeBackendError(
      `Optional specialized property membership is not backend-executable yet for ${field.name}.`,
    );
  }
  return [`${indent(level)}i32.const 1`];
}

